def read_virtuale_saldo() -> Decimal:
    """Saldo virtuale residuo da scaricare (persistente tra sessioni)."""
    try:
        if DEFAULT_VIRTUALE_SALDO_FILE.exists():
            return Decimal(str(json.loads(DEFAULT_VIRTUALE_SALDO_FILE.read_text(encoding="utf-8")).get("euro", "0")))
    except Exception:
        pass
    return Decimal("0")


def write_virtuale_saldo(value: Decimal) -> None:
    try:
        DEFAULT_VIRTUALE_SALDO_FILE.parent.mkdir(parents=True, exist_ok=True)
        v = value.quantize(Decimal("0.01"))
        if v <= 0:
            if DEFAULT_VIRTUALE_SALDO_FILE.exists():
                DEFAULT_VIRTUALE_SALDO_FILE.unlink()
        else:
            DEFAULT_VIRTUALE_SALDO_FILE.write_text(json.dumps({"euro": str(v)}), encoding="utf-8")
    except Exception:
        pass


def bind_entry_first_char_uppercase(var: tk.StringVar, entry: tk.Misc) -> None:
    """Il primo carattere del testo viene forzato in maiuscolo se immesso minuscolo."""
    lock: list[bool] = [False]

    def _on_write(*_args: object) -> None:
        if lock[0]:
            return
        s = var.get()
        if not s:
            return
        c0 = s[0]
        if not c0.islower():
            return
        try:
            pos = entry.index(tk.INSERT)
        except Exception:
            pos = None
        lock[0] = True
        try:
            var.set(c0.upper() + s[1:])
            if pos is not None:
                entry.icursor(min(pos, len(var.get())))
        finally:
            lock[0] = False

    var.trace_add("write", _on_write)


def bind_entry_all_chars_uppercase(var: tk.StringVar, entry: tk.Misc) -> None:
    """Forza in maiuscolo tutto il testo immesso mantenendo il cursore."""
    lock: list[bool] = [False]

    def _on_write(*_args: object) -> None:
        if lock[0]:
            return
        s = var.get()
        up = s.upper()
        if s == up:
            return
        try:
            pos = entry.index(tk.INSERT)
        except Exception:
            pos = None
        lock[0] = True
        try:
            var.set(up)
            if pos is not None:
                entry.icursor(min(pos, len(var.get())))
        finally:
            lock[0] = False

    var.trace_add("write", _on_write)


_EURO_TYPABLE_MINUS_CHARS = frozenset({"-", "\u2212", "\u2013"})


def _euro_typed_char_is_sign(ch: str) -> bool:
    return ch == "+" or ch in _EURO_TYPABLE_MINUS_CHARS


def _euro_sign_char_to_ascii(ch: str) -> str:
    return "-" if ch in _EURO_TYPABLE_MINUS_CHARS else "+"


def _euro_strip_leading_signs(s: str) -> str:
    t = s or ""
    while t and (t[0] == "+" or t[0] in _EURO_TYPABLE_MINUS_CHARS):
        t = t[1:]
    return t


def bind_euro_amount_entry_validation(
    entry: tk.Misc,
    var: tk.StringVar,
    *,
    allow_leading_sign: bool = True,
    require_leading_sign: bool = False,
    reject_zero: bool = False,
    max_decimals: int = 2,
    on_enter: Callable[[], object] | None = None,
    cursor_after_sign_on_focus: bool = False,
    external_focusout: bool = False,
    format_zero: bool = True,
) -> None:
    """
    Limita immissione e incolla a importi euro: cifre e separatori . e ,; + e − solo come primo carattere
    (sostituisce il segno esistente). Con allow_leading_sign=False (es. saldo cassa) non ammette segno.
    """

    max_decimals_int = max(0, int(max_decimals))
    _formatted_it_re = re.compile(r"^[+-]?(?:\d{1,3}(?:\.\d{3})+|\d+),\d{2}$")

    def _clear_entry_selection() -> None:
        try:
            entry.selection_clear()
        except Exception:
            pass

    def _focus_entry_select_all() -> None:
        """Ripristina focus e selezione totale dopo un messagebox (Aqua: evitare icursor dopo selection)."""

        def _apply() -> None:
            try:
                entry.focus_set()
            except Exception:
                return
            try:
                entry.update_idletasks()
                entry.selection_range(0, tk.END)
            except Exception:
                pass
            finally:
                try:
                    delattr(entry, "_cdc_euro_after_modal_refocus")
                except Exception:
                    pass

        try:
            # Doppio defer: dopo il dialog alcuni handler (es. FocusIn) alterano ancora insert/selection.
            entry.after_idle(lambda: entry.after(1, _apply))
        except Exception:
            try:
                entry.after(1, _apply)
            except Exception:
                _apply()

    def _after_modal_refocus_select_all() -> None:
        try:
            setattr(entry, "_cdc_euro_after_modal_refocus", True)
        except Exception:
            pass
        _focus_entry_select_all()

    def _set_amount_text_and_cursor(text: str, *, cursor: int | None = None, select_all: bool = False) -> None:
        var.set(text)
        try:
            if select_all:
                entry.selection_range(0, tk.END)
            elif cursor is None:
                entry.icursor(tk.END)
                _clear_entry_selection()
            else:
                entry.icursor(cursor)
                _clear_entry_selection()
        except Exception:
            pass

    def _msg_importo_non_valido() -> None:
        try:
            messagebox.showerror(
                "Importo non valido",
                "Inserisci un importo in euro valido (es. 1.234,56).",
                parent=entry,
            )
        except Exception:
            pass
        _after_modal_refocus_select_all()

    def _msg_importo_obbligatorio() -> None:
        try:
            messagebox.showwarning("Importo", "Importo obbligatorio.", parent=entry)
        except Exception:
            pass
        _after_modal_refocus_select_all()

    def _msg_zero_non_ammesso() -> None:
        try:
            messagebox.showerror("Importo", "Importo a zero non ammesso.", parent=entry)
        except Exception:
            pass
        _after_modal_refocus_select_all()

    def _normalize_on_enter() -> bool:
        raw = (var.get() or "").strip().replace(" ", "")
        if not raw or raw in ("+", "-"):
            if reject_zero and require_leading_sign and allow_leading_sign:
                _msg_zero_non_ammesso()
                return False
            if require_leading_sign and allow_leading_sign:
                _msg_importo_obbligatorio()
            return False
        try:
            val = normalize_euro_input(raw)
        except Exception:
            _msg_importo_non_valido()
            return False
        if reject_zero and val == Decimal("0.00"):
            _msg_zero_non_ammesso()
            return False
        if not format_zero and val == Decimal("0.00"):
            return False
        txt_abs = format_euro_it(abs(val))
        if allow_leading_sign:
            if val < 0:
                _set_amount_text_and_cursor("-" + txt_abs)
            elif require_leading_sign or raw.startswith("+"):
                _set_amount_text_and_cursor("+" + txt_abs)
            else:
                _set_amount_text_and_cursor(txt_abs)
        else:
            _set_amount_text_and_cursor(txt_abs)
        return True

    def _format_on_focus_out(_e: tk.Event | None = None) -> None:
        raw = (var.get() or "").strip().replace(" ", "")
        if not raw:
            if reject_zero and require_leading_sign and allow_leading_sign:
                _set_amount_text_and_cursor("-", cursor=1)
                _msg_zero_non_ammesso()
            return
        if raw in ("+", "-"):
            if reject_zero:
                _msg_zero_non_ammesso()
            return
        try:
            val = normalize_euro_input(raw)
        except Exception:
            _msg_importo_non_valido()
            return
        if reject_zero and val == Decimal("0.00"):
            txt_abs = format_euro_it(abs(val))
            if allow_leading_sign:
                if raw.startswith("-"):
                    sign = "-"
                elif raw.startswith("+"):
                    sign = "+"
                elif require_leading_sign:
                    sign = "+"
                else:
                    sign = ""
                _set_amount_text_and_cursor((sign + txt_abs) if sign else txt_abs, select_all=True)
            else:
                _set_amount_text_and_cursor(txt_abs, select_all=True)
            _msg_zero_non_ammesso()
            return
        if not format_zero and val == Decimal("0.00"):
            return
        txt_abs = format_euro_it(abs(val))
        if allow_leading_sign:
            if raw.startswith("-"):
                _set_amount_text_and_cursor("-" + txt_abs)
            elif raw.startswith("+"):
                _set_amount_text_and_cursor("+" + txt_abs)
            elif require_leading_sign:
                _set_amount_text_and_cursor("+" + txt_abs)
            elif val < 0:
                _set_amount_text_and_cursor("-" + txt_abs)
            else:
                _set_amount_text_and_cursor(txt_abs)
        else:
            _set_amount_text_and_cursor(txt_abs)

    def _on_double_click_select(event: tk.Event) -> str | None:
        w = event.widget
        s = str(var.get() or "")
        if not s:
            return None
        if _formatted_it_re.fullmatch(s):
            try:
                w.selection_range(0, tk.END)
                w.icursor(tk.END)
            except Exception:
                pass
            return "break"
        sign_off = 1 if s[:1] in ("+", "-") else 0
        body = s[sign_off:]
        sep_pos_body = -1
        if "," in body and "." in body:
            sep_pos_body = body.rfind(",")
        elif "," in body:
            sep_pos_body = body.find(",")
        elif "." in body:
            sep_pos_body = body.find(".")
        if sep_pos_body < 0:
            try:
                w.selection_range(0, tk.END)
                w.icursor(tk.END)
            except Exception:
                pass
            return "break"
        sep_abs = sign_off + sep_pos_body
        try:
            click_pos = int(w.index(f"@{int(getattr(event, 'x', 0) or 0)}"))
        except Exception:
            try:
                click_pos = int(w.index(tk.INSERT))
            except Exception:
                click_pos = len(s)
        try:
            if click_pos <= sep_abs:
                w.selection_range(0, sep_abs)
                w.icursor(sep_abs)
            else:
                w.selection_range(sep_abs + 1, tk.END)
                w.icursor(tk.END)
        except Exception:
            pass
        return "break"

    def _merged_after_edit(event: tk.Event, *, ins_ch: str | None = None) -> str | None:
        w = event.widget
        s = var.get() or ""
        try:
            if not int(w.selection_present()):
                raise tk.TclError("no selection")
            a = int(w.index("sel.first"))
            b = int(w.index("sel.last"))
        except tk.TclError:
            try:
                p = int(w.index(tk.INSERT))
            except tk.TclError:
                p = len(s)
            a = b = p
        keysym = str(getattr(event, "keysym", "") or "")
        ch = ins_ch if ins_ch is not None else str(getattr(event, "char", "") or "")
        try:
            p_ins = int(w.index(tk.INSERT))
        except tk.TclError:
            p_ins = len(s)
        if keysym == "BackSpace":
            if a != b:
                return s[:a] + s[b:]
            if p_ins <= 0:
                return s
            return s[: p_ins - 1] + s[p_ins:]
        if keysym == "Delete":
            if a != b:
                return s[:a] + s[b:]
            if p_ins >= len(s):
                return s
            return s[:p_ins] + s[p_ins + 1 :]
        if ch and ord(ch) >= 32:
            return s[:a] + ch + s[b:] if a != b else (s[:p_ins] + ch + s[p_ins:])
        return None

    def _typed_symbol_from_key_event(event: tk.Event) -> str | None:
        ch = str(getattr(event, "char", "") or "")
        if ch and ord(ch) >= 32:
            return ch
        keysym = str(getattr(event, "keysym", "") or "")
        if len(keysym) == 1 and keysym.isdigit():
            return keysym
        kp_map = {
            "KP_0": "0",
            "KP_1": "1",
            "KP_2": "2",
            "KP_3": "3",
            "KP_4": "4",
            "KP_5": "5",
            "KP_6": "6",
            "KP_7": "7",
            "KP_8": "8",
            "KP_9": "9",
            "KP_Decimal": ".",
            "KP_separator": ",",
            "KP_Add": "+",
            "KP_Subtract": "-",
        }
        if keysym in kp_map:
            return kp_map[keysym]
        if keysym in ("period", "comma"):
            return "." if keysym == "period" else ","
        return None

    def _is_partial_valid(text: str) -> bool:
        t = (text or "").replace(" ", "")
        if t == "":
            return True
        if not allow_leading_sign and (t.startswith("+") or t.startswith("-")):
            return False
        if require_leading_sign and allow_leading_sign and not t.startswith(("+", "-")):
            return False
        if not re.fullmatch(r"[0-9+\-.,]*", t):
            return False
        body = t
        if allow_leading_sign and t.startswith(("+", "-")):
            body = t[1:]
        if "+" in body or "-" in body:
            return False
        if body.count(".") + body.count(",") > 1:
            return False
        if "." in body:
            left, right = body.split(".", 1)
            if left and not left.isdigit():
                return False
            if right and not right.isdigit():
                return False
            if len(right) > max_decimals_int:
                return False
        if "," in body:
            left, right = body.split(",", 1)
            if left and not left.isdigit():
                return False
            if right and not right.isdigit():
                return False
            if len(right) > max_decimals_int:
                return False
        if "." not in body and "," not in body and body and not body.isdigit():
            return False
        return True

    def _ensure_require_leading_sign_on_edit(nxt: str, prev_s: str) -> str:
        """Se serve +/- in testa e il merge ha perso il segno (es. selezione totale + cifra), ripristinalo."""
        if not (require_leading_sign and allow_leading_sign) or not nxt:
            return nxt
        t = (nxt or "").replace("\u2212", "-").replace("\u2013", "-")
        if t.startswith(("+", "-")):
            return nxt
        ps = prev_s or ""
        lead = "-"
        if ps.startswith("+"):
            lead = "+"
        elif ps.startswith("-"):
            lead = "-"
        return lead + t

    def _keypress(event: tk.Event) -> str | None:
        keysym = getattr(event, "keysym", "")
        if keysym in ("Return", "KP_Enter"):
            if _normalize_on_enter() and on_enter is not None:
                on_enter()
            return "break"
        if keysym in (
            "Left",
            "Right",
            "Up",
            "Down",
            "Home",
            "End",
            "Tab",
            "ISO_Left_Tab",
            "Escape",
            "Prior",
            "Next",
        ):
            return None
        if keysym in ("BackSpace", "Delete"):
            nxt = _merged_after_edit(event)
            if nxt is None or not _is_partial_valid(nxt):
                return "break"
            if require_leading_sign and allow_leading_sign:
                if nxt == "":
                    cur = var.get() or ""
                    keep = "+"
                    if cur.startswith("-"):
                        keep = "-"
                    elif cur.startswith("+"):
                        keep = "+"
                    var.set(keep)
                    try:
                        event.widget.icursor(1)
                        _clear_entry_selection()
                    except Exception:
                        pass
                    return "break"
                if not nxt.startswith(("+", "-")):
                    return "break"
            return None
        sym = _typed_symbol_from_key_event(event)
        if not sym:
            return None
        st = int(getattr(event, "state", 0) or 0)
        if st & (0x0004 | 0x0008 | 0x20000 | 0x100000):
            return None

        w = event.widget
        s = var.get() or ""

        if _euro_typed_char_is_sign(sym):
            if not allow_leading_sign:
                return "break"
            sig = _euro_sign_char_to_ascii(sym)
            body = _euro_strip_leading_signs(s)
            if not body:
                _set_amount_text_and_cursor(sig, cursor=1)
            else:
                lead = s[:1]
                lead_sig = _euro_sign_char_to_ascii(lead) if lead and _euro_typed_char_is_sign(lead) else None
                if lead_sig is None or lead_sig != sig:
                    _set_amount_text_and_cursor(sig + body)
                else:
                    _set_amount_text_and_cursor(s)
            return "break"

        if sym.isdigit() or sym in ",.":
            merged_raw = _merged_after_edit(event, ins_ch=sym)
            if merged_raw is None:
                return "break"
            nxt = _ensure_require_leading_sign_on_edit(merged_raw, s)
            if not _is_partial_valid(nxt):
                return "break"
            # Se _ensure_require_leading_sign_on_edit antepone +/-, il testo si allunga in testa:
            # il cursore va spostato in avanti di altrettanti caratteri, altrimenti la prossima cifra
            # finisce tra segno e prima cifra (es. "+25" → "+52").
            sign_extra = len(nxt) - len(merged_raw)
            try:
                if not int(w.selection_present()):
                    raise tk.TclError("no selection")
                a = int(w.index("sel.first"))
                b = int(w.index("sel.last"))
            except tk.TclError:
                a = b = -1
            if a != b and a >= 0:
                new_pos = min(a + len(sym) + sign_extra, len(nxt))
            else:
                new_pos = None
            _set_amount_text_and_cursor(nxt, cursor=new_pos)
            return "break"
        return "break"

    def _paste(event: tk.Event) -> str:
        try:
            clip = event.widget.clipboard_get()
        except tk.TclError:
            return "break"
        t = clip.strip().replace(" ", "").replace("\u2212", "-").replace("\u2013", "-")
        if not t:
            return "break"
        w = event.widget
        s = var.get() or ""
        try:
            a = int(w.index("sel.first"))
            b = int(w.index("sel.last"))
        except tk.TclError:
            try:
                p = int(w.index(tk.INSERT))
            except tk.TclError:
                return "break"
            a = b = p
        merged_raw = (s[:a] + t + s[b:]).replace("\u2212", "-").replace("\u2013", "-").replace(" ", "")
        merged = _ensure_require_leading_sign_on_edit(merged_raw, s)
        if not _is_partial_valid(merged):
            return "break"
        sign_extra = len(merged) - len(merged_raw)
        cur = min(a + len(t) + sign_extra, len(merged))
        _set_amount_text_and_cursor(merged, cursor=cur)
        return "break"

    # Esegui validazione tasti prima dei binding di classe (es. TEntry), così
    # return "break" impedisce davvero l'inserimento predefinito (sostituzione selezione).
    try:
        bind_tag = getattr(entry, "_cdc_euro_amount_bindtag", None)
        if not bind_tag:
            bind_tag = f"_cdc_euro_amt_{id(entry)}"
            setattr(entry, "_cdc_euro_amount_bindtag", bind_tag)
            tags = list(entry.bindtags())
            if bind_tag not in tags:
                ins_at = 1 if len(tags) > 1 else 0
                tags.insert(ins_at, bind_tag)
                entry.bindtags(tuple(tags))
        root = entry.winfo_toplevel()
        root.bind_class(bind_tag, "<KeyPress>", _keypress)
        root.bind_class(bind_tag, "<<Paste>>", _paste)
    except Exception:
        entry.bind("<KeyPress>", _keypress, add="+")
        entry.bind("<<Paste>>", _paste, add="+")
    entry.bind("<Double-Button-1>", _on_double_click_select, add="+")
    if not external_focusout:
        entry.bind("<FocusOut>", _format_on_focus_out, add="+")
    if cursor_after_sign_on_focus:
        def _focus_set_cursor(_e: tk.Event | None = None) -> None:
            if getattr(entry, "_cdc_euro_after_modal_refocus", False):
                return
            raw = (var.get() or "").strip()
            if require_leading_sign and allow_leading_sign and raw == "":
                try:
                    var.set("-")
                    raw = "-"
                except Exception:
                    pass
            try:
                if raw in ("+", "-"):
                    entry.icursor(1)
                else:
                    entry.icursor(tk.END)
                _clear_entry_selection()
            except Exception:
                pass

        entry.bind("<FocusIn>", _focus_set_cursor, add="+")


def _ttk_combobox_collect_listboxes(w: tk.Misc, acc: list[tk.Misc]) -> None:
    try:
        cls = str(w.winfo_class())
    except tk.TclError:
        return
    # Su alcune build Tk (soprattutto popdown ttk::combobox) la classe può non essere
    # esattamente "Listbox" ma includerla nel nome (es. "ComboboxListbox").
    if cls == "Listbox" or "listbox" in cls.lower():
        acc.append(w)
    try:
        kids = w.tk.splitlist(w.tk.call("winfo", "children", w))
    except tk.TclError:
        return
    for ch in kids:
        try:
            child = w.nametowidget(ch)
        except KeyError:
            continue
        _ttk_combobox_collect_listboxes(child, acc)


def _ttk_collect_widget_tree(w: tk.Misc, acc: list[tk.Misc]) -> None:
    acc.append(w)
    try:
        kids = w.tk.splitlist(w.tk.call("winfo", "children", w))
    except tk.TclError:
        return
    for ch in kids:
        try:
            child = w.nametowidget(ch)
        except KeyError:
            continue
        _ttk_collect_widget_tree(child, acc)


def _ttk_combobox_sync_open_popdown_selection(cb: ttk.Combobox, index: int) -> None:
    """
    Se il dropdown della combobox è aperto, allinea evidenziazione/scroll della listbox popup
    alla voce selezionata via tastiera.
    """
    try:
        i = int(index)
    except (TypeError, ValueError):
        return
    if i < 0:
        return
    try:
        pop_path = str(cb.tk.call("ttk::combobox::PopdownWindow", cb))
        if not bool(int(cb.tk.call("winfo", "ismapped", pop_path))):
            return
    except (tk.TclError, ValueError, TypeError):
        return
    # Struttura standard Tk/ttk combobox popup: <popdown>.f.l
    lb_path = f"{pop_path}.f.l"
    try:
        cb.tk.call(lb_path, "selection", "clear", 0, "end")
        cb.tk.call(lb_path, "selection", "set", i)
        cb.tk.call(lb_path, "activate", i)
        cb.tk.call(lb_path, "see", i)
    except tk.TclError:
        pass


def bind_ttk_combobox_letter_jump_with_popdown(
    cb: ttk.Combobox,
    *,
    on_letter: Callable[[str], bool],
) -> Callable[[], None]:
    """
    Salto alla prima voce che inizia con la lettera (case-insensitive), anche con il menu aperto.
    Ogni pressione è una lettera singola (nessun prefisso cumulativo): on_letter viene chiamata con quella sola lettera.
    on_letter(letter_lower) → True se il tasto è stato gestito.
    Ritorna una funzione cleanup (chiusura dialog o smontaggio widget).
    """
    popdown_widget_keypress_binds: list[tuple[tk.Misc, str, str]] = []
    popdown_listbox_binds: list[tuple[tk.Misc, str, str]] = []
    popdown_listbox_bindtags_restore: list[tuple[tk.Misc, tuple[str, ...]]] = []
    popdown_class_binds: list[tuple[tk.Misc, str, str, str]] = []
    combo_script_ids: list[tuple[str, str]] = []
    root_script_ids: list[tuple[tk.Misc, str, str]] = []
    class_script_ids: list[tuple[tk.Misc, str, str]] = []
    global_script_ids: list[str] = []

    def _is_this_combobox_popdown_open() -> bool:
        try:
            pop_path = str(cb.tk.call("ttk::combobox::PopdownWindow", cb))
        except tk.TclError:
            return False
        try:
            # Su macOS il popdown può non essere risolvibile con ``nametowidget``:
            # verifica direttamente via Tcl se la finestra è mappata.
            return bool(int(cb.tk.call("winfo", "ismapped", pop_path)))
        except (tk.TclError, ValueError, TypeError):
            return False

    def _letter_keypress(ev: tk.Event) -> str | None:
        try:
            if int(getattr(ev, "state", 0) or 0) & 0x14:
                return None
        except Exception:
            pass
        ch = str(getattr(ev, "char", "") or "")
        keysym = str(getattr(ev, "keysym", "") or "")
        letter = ""
        if len(ch) == 1 and ch.isalpha():
            letter = ch.lower()
        elif len(keysym) == 1 and keysym.isalpha():
            letter = keysym.lower()
        if not letter:
            return None
        handled = bool(on_letter(letter))
        return "break" if handled else None

    def _cleanup_popdown_binds() -> None:
        for ww, seq, bid in popdown_widget_keypress_binds:
            try:
                ww.unbind(seq, bid)
            except tk.TclError:
                pass
        popdown_widget_keypress_binds.clear()
        for lb, seq, bid in popdown_listbox_binds:
            try:
                lb.unbind(seq, bid)
            except tk.TclError:
                pass
        popdown_listbox_binds.clear()
        for lb, tags in popdown_listbox_bindtags_restore:
            try:
                lb.bindtags(tags)
            except tk.TclError:
                pass
        popdown_listbox_bindtags_restore.clear()
        for owner, tag, seq, bid in popdown_class_binds:
            try:
                owner.unbind_class(tag, seq, bid)
            except tk.TclError:
                pass
        popdown_class_binds.clear()
        for seq in reversed(global_script_ids):
            try:
                cb.unbind_all(seq)
            except tk.TclError:
                pass
        global_script_ids.clear()

    def _on_combobox_dropdown(_e: tk.Event | None = None) -> None:
        _cleanup_popdown_binds()

        def _attach() -> None:
            try:
                pop_path = str(cb.tk.call("ttk::combobox::PopdownWindow", cb))
            except tk.TclError:
                return
            try:
                pop_root = cb.nametowidget(pop_path)
            except (tk.TclError, KeyError):
                # Ambiente (Tk/Aqua) dove il popdown non è un widget tkinter risolvibile:
                # in questo caso restano attivi i fallback globali (bind_all/root/class).
                return
            all_widgets: list[tk.Misc] = []
            _ttk_collect_widget_tree(pop_root, all_widgets)
            for ww in all_widgets:
                def _ww_key(e: tk.Event) -> str | None:
                    return _letter_keypress(e)

                try:
                    bid = ww.bind("<KeyPress>", _ww_key, add="+")
                    popdown_widget_keypress_binds.append((ww, "<KeyPress>", bid))
                except tk.TclError:
                    pass
            boxes: list[tk.Misc] = []
            _ttk_combobox_collect_listboxes(pop_root, boxes)
            for lb in boxes:

                def _lb_key(e: tk.Event) -> str | None:
                    return _letter_keypress(e)

                try:
                    bid = lb.bind("<KeyPress>", _lb_key, add="+")
                    popdown_listbox_binds.append((lb, "<KeyPress>", bid))
                except tk.TclError:
                    pass
                # macOS/Tk: il bind di classe Listbox può consumare i tasti prima dei bind aggiunti.
                # Inseriamo un bindtag custom PRIMA di "Listbox", così la selezione lettere viene
                # gestita anche con menu aperto.
                try:
                    tags_now = tuple(str(t) for t in lb.bindtags())
                    custom_tag = f"CdcComboLetterJump_{cb.winfo_id()}"
                    if custom_tag not in tags_now:
                        popdown_listbox_bindtags_restore.append((lb, tags_now))
                        tags_new = list(tags_now)
                        if "Listbox" in tags_new:
                            i = tags_new.index("Listbox")
                            tags_new.insert(i, custom_tag)
                        else:
                            tags_new.insert(0, custom_tag)
                        lb.bindtags(tuple(tags_new))
                    bid_cls = lb.bind_class(custom_tag, "<KeyPress>", _lb_key, add="+")
                    popdown_class_binds.append((lb, custom_tag, "<KeyPress>", bid_cls))
                except tk.TclError:
                    pass

        try:
            cb.after_idle(_attach)
        except tk.TclError:
            pass

    def _on_combobox_close(_e: tk.Event | None = None) -> None:
        _cleanup_popdown_binds()

    def _on_root_keypress(ev: tk.Event) -> str | None:
        # Fallback robusto: su alcune piattaforme il popup aperto non inoltra sempre
        # il KeyPress ai bind della listbox interna.
        if not _is_this_combobox_popdown_open():
            return None
        return _letter_keypress(ev)

    try:
        combo_script_ids.append(("<KeyPress>", cb.bind("<KeyPress>", _letter_keypress, add="+")))
        combo_script_ids.append(("<<ComboboxDropdown>>", cb.bind("<<ComboboxDropdown>>", _on_combobox_dropdown, add="+")))
        combo_script_ids.append(("<<ComboboxClose>>", cb.bind("<<ComboboxClose>>", _on_combobox_close, add="+")))
        # Fallback robusto cross-platform: alcuni Tk/macOS non emettono sempre
        # <<ComboboxDropdown>>. Forziamo l'attach anche su click/freccia in apertura.
        combo_script_ids.append(("<Button-1>", cb.bind("<Button-1>", lambda _e: cb.after_idle(_on_combobox_dropdown), add="+")))
        combo_script_ids.append(("<Down>", cb.bind("<Down>", lambda _e: cb.after_idle(_on_combobox_dropdown), add="+")))
    except tk.TclError:
        pass
    try:
        cb.bind_all("<KeyPress>", _on_root_keypress, add="+")
        global_script_ids.append("<KeyPress>")
    except tk.TclError:
        pass
    try:
        rt = cb.winfo_toplevel()
        root_script_ids.append(("<KeyPress>", rt.bind("<KeyPress>", _on_root_keypress, add="+")))
        # macOS/Tk: quando il popdown è aperto, il focus è spesso sulla Listbox interna
        # e il bind sulla toplevel può non scattare. Aggancio anche il bind di classe.
        class_script_ids.append((
            "Listbox",
            "<KeyPress>",
            rt.bind_class("Listbox", "<KeyPress>", _on_root_keypress, add="+"),
        ))
    except tk.TclError:
        pass

    def _full_cleanup() -> None:
        _cleanup_popdown_binds()
        for seq, bid in reversed(root_script_ids):
            try:
                cb.winfo_toplevel().unbind(seq, bid)
            except tk.TclError:
                pass
        root_script_ids.clear()
        for cls, seq, bid in reversed(class_script_ids):
            try:
                cb.winfo_toplevel().unbind_class(cls, seq, bid)
            except tk.TclError:
                pass
        class_script_ids.clear()
        for seq, bid in reversed(combo_script_ids):
            try:
                cb.unbind(seq, bid)
            except tk.TclError:
                pass
        combo_script_ids.clear()

    return _full_cleanup


def bind_ttk_combobox_prefix_letter_jump(
    cb: ttk.Combobox,
    *,
    on_pick: Callable[[str, int], None],
    skip_value: Callable[[str], bool] | None = None,
    reset_ms: int = 900,
) -> Callable[[], None]:
    """
    Salto letterale con prefisso cumulativo (es. ``ca``) su combobox readonly.
    Usa anche il supporto popup aperto di ``bind_ttk_combobox_letter_jump_with_popdown``.
    """
    typed_prefix: list[str] = [""]
    reset_after_id: list[str | None] = [None]

    def _cancel_reset_timer() -> None:
        aid = reset_after_id[0]
        if aid:
            try:
                cb.after_cancel(aid)
            except Exception:
                pass
        reset_after_id[0] = None

    def _reset_prefix() -> None:
        _cancel_reset_timer()
        typed_prefix[0] = ""

    def _schedule_reset() -> None:
        _cancel_reset_timer()
        try:
            reset_after_id[0] = cb.after(max(200, int(reset_ms)), _reset_prefix)
        except Exception:
            reset_after_id[0] = None

    def _select_first_startswith(prefix: str) -> bool:
        try:
            vals = list(cb.cget("values") or ())
        except tk.TclError:
            return False
        pref = (prefix or "").strip().lower()
        if not vals or not pref:
            return False
        for idx, nm in enumerate(vals):
            sn = str(nm or "").strip()
            if not sn:
                continue
            if skip_value is not None and skip_value(sn):
                continue
            if not sn.lower().startswith(pref):
                continue
            on_pick(sn, idx)
            _ttk_combobox_sync_open_popdown_selection(cb, idx)
            return True
        return False

    def _on_letter(letter: str) -> bool:
        typed_prefix[0] = (typed_prefix[0] + letter).lower()
        _schedule_reset()
        if _select_first_startswith(typed_prefix[0]):
            return True
        typed_prefix[0] = letter.lower()
        return _select_first_startswith(typed_prefix[0])

    cleanup = bind_ttk_combobox_letter_jump_with_popdown(cb, on_letter=_on_letter)

    def _full_cleanup() -> None:
        _cancel_reset_timer()
        cleanup()

    return _full_cleanup


def to_italian_date(date_iso: str) -> str:
    parts = date_iso.split("-")
    if len(parts) != 3:
        return date_iso
    yyyy, mm, dd = parts
    return f"{dd}/{mm}/{yyyy}"


def parse_italian_ddmmyyyy_to_iso(s: str) -> str | None:
    """Come i campi data in Movimenti: gg/mm/aaaa o gg/mm/aa (anno a 2 cifre → 2000–2099) o ISO YYYY-MM-DD."""
    s = (s or "").strip()
    if not s:
        return None
    if "-" in s:
        parts = s.split("-")
        if len(parts) == 3:
            try:
                return date.fromisoformat(s).isoformat()
            except Exception:
                return None
    parts = s.split("/")
    if len(parts) != 3:
        return None
    dd, mm, y_raw = parts
    if not (dd.isdigit() and mm.isdigit() and y_raw.isdigit()):
        return None
    if len(y_raw) == 2:
        yi = int(y_raw)
        yyyy = 2000 + yi if yi <= 99 else yi
    elif len(y_raw) == 4:
        yyyy = int(y_raw)
    else:
        return None
    try:
        return date(yyyy, int(mm), int(dd)).isoformat()
    except Exception:
        return None


def date_minus_calendar_years(d: date, years: int) -> date:
    y = d.year - years
    m, day = d.month, d.day
    last = calendar.monthrange(y, m)[1]
    return date(y, m, min(day, last))


def years_for_calendar_option_menu(available: list[int], *, pin_year: int) -> list[int]:
    """
    Tendine anni per calendari: ``pin_year`` in cima (l'anno "corrente" d'uso), resto in ordine decrescente.
    I valori in ``available`` devono corrispondere a anni consentiti; elenco duplicati ammessi, ignorati.
    Se ``pin_year`` non compare tra i disponibili, si usa solo l'elenco in decrescente.
    """
    ys = sorted({int(y) for y in available}, reverse=True)
    if not ys:
        return []
    ypin = int(pin_year)
    if ypin in ys:
        return [ypin] + [y for y in ys if y != ypin]
    return ys


def immissione_date_bounds(today: date | None = None) -> tuple[date, date]:
    """Intervallo date per nuova registrazione e periodiche: −1 anno / +1 anno da oggi."""
    t = today or date.today()
    return (date_minus_calendar_years(t, 1), date_minus_calendar_years(t, -1))


def build_immissione_calendar_toplevel(
    root: tk.Misc,
    *,
    title: str,
    anchor: tk.Misc,
    field_min: date,
    field_max: date,
    current: date,
    on_date_chosen: Callable[[date], None],
    ui_font: tuple = ("TkDefaultFont", 12, "bold"),
) -> tk.Toplevel:
    """
    Popup calendario allineato ai filtri data Movimenti (layout compatto, sotto il campo,
    anni nel range, giorni fuori range disabilitati). Non modale (grab rilasciato).
    """
    if field_min > field_max:
        field_min, field_max = field_max, field_min
    cur = current
    if cur < field_min:
        cur = field_min
    if cur > field_max:
        cur = field_max

    top = tk.Toplevel(root)
    top.title(title)
    top.transient(root)
    try:
        top.withdraw()
    except Exception:
        pass
    try:
        top.grab_release()
    except Exception:
        pass
    top.protocol("WM_DELETE_WINDOW", lambda: top.destroy())

    selected_date = cur
    cur_year = cur.year
    cur_month = cur.month

    years_available = [y for y in range(field_min.year, field_max.year + 1)]
    if not years_available:
        years_available = [cur_year]
    if cur_year not in years_available:
        higher = [y for y in years_available if y >= cur_year]
        cur_year = min(higher) if higher else max(years_available)

    header = ttk.Frame(top, padding=6)
    header.pack(fill=tk.X)
    title_lbl = ttk.Label(header, font=("TkDefaultFont", 10, "bold"))
    title_lbl.pack(side=tk.LEFT)

    btns = ttk.Frame(header)
    btns.pack(side=tk.RIGHT)

    def _prev_month(y: int, m: int) -> tuple[int, int]:
        return (y - 1, 12) if m == 1 else (y, m - 1)

    def _next_month(y: int, m: int) -> tuple[int, int]:
        return (y + 1, 1) if m == 12 else (y, m + 1)

    def _cell_pick(dsel: date) -> None:
        on_date_chosen(dsel)
        try:
            top.destroy()
        except Exception:
            pass

    def render() -> None:
        nonlocal cur_year, cur_month
        for child in list(days_frame.winfo_children()):
            child.destroy()
        title_lbl.configure(text=f"{calendar.month_name[cur_month]} {cur_year}")
        _update_month_nav_state()
        nonlocal suppress_year_trace
        if year_var.get() != str(cur_year):
            suppress_year_trace = True
            year_var.set(str(cur_year))
            suppress_year_trace = False

        first_wd = date(cur_year, cur_month, 1).weekday()
        days_in_month = calendar.monthrange(cur_year, cur_month)[1]

        for i in range(first_wd):
            ttk.Label(days_frame, text="").grid(row=0, column=i, padx=1, pady=1, sticky="nsew")

        for day_num in range(1, days_in_month + 1):
            idx = first_wd + day_num - 1
            row = idx // 7
            col = idx % 7
            dsel = date(cur_year, cur_month, day_num)
            in_bounds = field_min <= dsel <= field_max
            cell = tk.Label(
                days_frame,
                text=str(day_num),
                width=3,
                padx=2,
                pady=2,
                fg="#111111",
                bg=CDC_CAL_CELL_BG,
                relief=tk.RAISED,
                bd=1,
                highlightthickness=0,
                font=ui_font,
            )
            if in_bounds:
                cell.configure(cursor="hand2")
                cell.bind("<Button-1>", lambda _e, dd=dsel: _cell_pick(dd))
            else:
                cell.configure(fg=CDC_CAL_DISABLED_LABEL_FG, bg=CDC_CAL_DISABLED_BG)

            if dsel == selected_date:
                cell.configure(
                    bg=CDC_CAL_SELECTED_BG,
                    relief=tk.SUNKEN,
                    bd=2,
                    highlightthickness=1,
                    highlightbackground="#5fa8c4",
                    highlightcolor="#5fa8c4",
                )

            cell.grid(row=row + 1, column=col, padx=1, pady=1, sticky="nsew")

        for c in range(7):
            days_frame.grid_columnconfigure(c, weight=1)

    year_var = tk.StringVar(value=str(cur_year))
    _years_in_menu = years_for_calendar_option_menu(
        years_available, pin_year=date.today().year
    )
    year_menu = tk.OptionMenu(btns, year_var, *[str(y) for y in _years_in_menu])
    year_menu.pack(side=tk.LEFT, padx=(0, 6))

    suppress_year_trace = False

    def _on_year_changed(*_args: object) -> None:
        nonlocal cur_year
        if suppress_year_trace:
            return
        y = int(year_var.get())
        if y == cur_year:
            return
        cur_year = y
        render()

    year_var.trace_add("write", _on_year_changed)

    btn_month_minus = ttk.Button(btns, text="<<", command=lambda: _jump_month(-1))
    btn_month_plus = ttk.Button(btns, text=">>", command=lambda: _jump_month(1))
    btn_month_minus.pack(side=tk.LEFT, padx=(0, 4))
    btn_month_plus.pack(side=tk.LEFT, padx=(0, 0))

    min_month_key = (field_min.year, field_min.month)
    max_month_key = (field_max.year, field_max.month)

    def _month_key(y: int, m: int) -> tuple[int, int]:
        return (y, m)

    def _update_month_nav_state() -> None:
        prev_y, prev_m = _prev_month(cur_year, cur_month)
        next_y, next_m = _next_month(cur_year, cur_month)
        btn_month_minus.configure(
            state=("normal" if _month_key(prev_y, prev_m) >= min_month_key else "disabled")
        )
        btn_month_plus.configure(
            state=("normal" if _month_key(next_y, next_m) <= max_month_key else "disabled")
        )

    def _jump_month(delta: int) -> None:
        nonlocal cur_year, cur_month
        if delta < 0:
            cur_year, cur_month = _prev_month(cur_year, cur_month)
        else:
            cur_year, cur_month = _next_month(cur_year, cur_month)
        if cur_year not in years_available:
            higher = [y for y in years_available if y >= cur_year]
            cur_year = min(higher) if higher else max(years_available)
        nonlocal suppress_year_trace
        if year_var.get() != str(cur_year):
            suppress_year_trace = True
            year_var.set(str(cur_year))
            suppress_year_trace = False
        render()

    labels = ttk.Frame(top, padding=(6, 0, 6, 0))
    labels.pack(fill=tk.X)
    for i, name in enumerate(["Lun", "Mar", "Mer", "Gio", "Ven", "Sab", "Dom"]):
        ttk.Label(labels, text=name, font=ui_font).grid(row=0, column=i, padx=1, pady=2, sticky="nsew")

    days_frame = tk.Frame(top, padx=6, pady=6)
    days_frame.pack(fill=tk.BOTH, expand=True)
    for c in range(7):
        days_frame.grid_columnconfigure(c, weight=1)

    footer = ttk.Frame(top, padding=6)
    footer.pack(fill=tk.X)
    ttk.Button(
        footer,
        text="Oggi",
        command=lambda: _on_pick_today(),
    ).pack(side=tk.LEFT)

    def _on_pick_today() -> None:
        tdy = date.today()
        picked = max(field_min, min(tdy, field_max))
        on_date_chosen(picked)
        try:
            top.destroy()
        except Exception:
            pass

    render()

    def _place_calendar_below_anchor() -> None:
        try:
            top.update_idletasks()
            root.update_idletasks()
            ex = int(anchor.winfo_rootx())
            ey_top = int(anchor.winfo_rooty())
            ey_bottom = int(ey_top + anchor.winfo_height())
            w = max(1, int(top.winfo_reqwidth()))
            h = max(1, int(top.winfo_reqheight()))
            scr_w = int(top.winfo_screenwidth())
            scr_h = int(top.winfo_screenheight())
            gap = 4
            x = ex
            y = ey_bottom + gap
            if x + w > scr_w - 10:
                x = max(10, scr_w - w - 10)
            if y + h > scr_h - 10:
                y = ey_top - h - gap
            if y < 10:
                y = 10
            top.geometry(f"{w}x{h}+{x}+{y}")
        except Exception:
            pass

    _place_calendar_below_anchor()
    try:
        top.deiconify()
        top.lift()
    except Exception:
        pass
    try:
        top.focus_force()
    except Exception:
        pass
    return top


def record_is_within_edit_age(rec: dict, *, today: date | None = None) -> bool:
    """False se la data registrazione è più vecchia di 5 anni rispetto a oggi."""
    today = today or date.today()
    iso = str(rec.get("date_iso", "")).strip()
    if not iso:
        return False
    try:
        rd = date.fromisoformat(iso)
    except Exception:
        return False
    cutoff = date_minus_calendar_years(today, 5)
    return rd >= cutoff


def record_is_within_forza_verifica_recency(rec: dict, *, today: date | None = None) -> bool:
    """True se la registrazione non è più vecchia di 1 anno rispetto a oggi (pulsante Forza verifica)."""
    today = today or date.today()
    iso = str(rec.get("date_iso", "")).strip()
    if not iso:
        return False
    try:
        rd = date.fromisoformat(iso)
    except Exception:
        return False
    cutoff = date_minus_calendar_years(today, 1)
    return rd >= cutoff


def record_has_account_verification_flags(rec: dict) -> bool:
    """Asterisco/i accanto al conto: blocca modifica conti e importo."""
    f1 = str(rec.get("account_primary_flags") or "")
    f2 = str(rec.get("account_secondary_flags") or "")
    return "*" in f1 or "*" in f2


# Blocco modifica/elimina in Movimenti: le registrazioni con data anteriore a questa non sono modificabili/eliminabili.
RECORD_MOD_DELETE_CUTOFF_DATE = date(2021, 1, 1)


def record_is_within_recent_mod_delete_window(rec: dict) -> bool:
    """
    Modifica/elimina in Movimenti consentite se ``date_iso`` non è anteriore a
    ``RECORD_MOD_DELETE_CUTOFF_DATE`` (1° gennaio 2021).
    """
    iso = str(rec.get("date_iso", "")).strip()
    if not iso:
        return False
    try:
        rd = date.fromisoformat(iso)
    except Exception:
        return False
    return rd >= RECORD_MOD_DELETE_CUTOFF_DATE


def record_is_before_2022(rec: dict) -> bool:
    iso = str(rec.get("date_iso", "")).strip()
    if not iso:
        return False
    try:
        rd = date.fromisoformat(iso)
    except Exception:
        return False
    return rd < date(2022, 1, 1)


def record_contains_any_asterisk(rec: dict) -> bool:
    """True se qualunque campo stringa della registrazione contiene '*'."""
    for v in rec.values():
        if isinstance(v, str) and "*" in v:
            return True
    return False


def normalize_category_leading_sign_in_stored(raw: str) -> str:
    """Normalizza spazi iniziali/finali del nome categoria memorizzato (segno + o - esplicito)."""
    return (raw or "").strip()


def strip_residual_category_display_prefix(name: str) -> str:
    """Rimuove ``=`` residui all'inizio (legacy / import) per la sola visualizzazione."""
    return (name or "").strip().lstrip("=").strip()


def category_display_name(raw: str) -> str:
    base = normalize_category_leading_sign_in_stored((raw or "").strip())
    base = strip_residual_category_display_prefix(base)
    return base[1:].strip() if base[:1] in {"+", "-"} else base


def format_category_chart_name_stored(raw: str) -> str:
    """Nome categoria nel piano: segno + o -, corpo maiuscolo, lunghezza massima."""
    t = normalize_category_leading_sign_in_stored((raw or "").strip())
    if not t:
        return clip_text("+", MAX_CATEGORY_NAME_LEN)
    sign = t[0] if t[0] in "+-" else "+"
    body = (t[1:] if t[0] in "+-" else t).strip().upper()
    return clip_text(sign + body, MAX_CATEGORY_NAME_LEN)


def format_category_note_stored(note: str) -> str:
    t = clip_text((note or "").strip(), MAX_CATEGORY_NOTE_LEN)
    if not t:
        return t
    return t[0].upper() + t[1:]


def format_record_note_stored(note: str) -> str:
    """Nota da salvare: preserva spazi iniziali/finali; primo carattere alfabetico minuscolo → maiuscolo."""
    t = clip_text(note or "", MAX_RECORD_NOTE_LEN)
    if not t.strip():
        return ""
    i = 0
    while i < len(t) and t[i].isspace():
        i += 1
    if i >= len(t):
        return t
    c = t[i]
    if c.islower():
        t = t[:i] + c.upper() + t[i + 1 :]
    return t


def sync_record_category_names_if_identical_old(
    db: dict,
    code: str,
    old_name: str,
    new_canonical: str,
    *,
    min_year: int | None = None,
) -> None:
    """Aggiorna le registrazioni con `category_name` identico al nome precedente (e stesso codice), opz. da un anno in poi.

    `min_year` (es. 2022) evita toccare registrazioni legacy pre-2022, coerentemente con l’export JSON in ``legacy_import``."""
    sc = str(code).strip()
    old_s = (old_name or "").strip()
    for yb in db.get("years", []) or []:
        if min_year is not None:
            try:
                if int(yb.get("year", 0) or 0) < int(min_year):
                    continue
            except (TypeError, ValueError):
                continue
        for r in yb.get("records", []) or []:
            if str(r.get("category_code", "")).strip() != sc:
                continue
            if (r.get("category_name") or "").strip() != old_s:
                continue
            r["category_name"] = new_canonical


def is_hidden_dotazione_category_name(raw: str) -> bool:
    """True se l’etichetta è la categoria legacy «dotazione iniziale» (mai mostrata in elenchi/UI)."""
    disp = category_display_name(raw or "").strip().lower()
    if not disp:
        return False
    norm = " ".join(disp.replace(".", " ").split())
    return "dotazione" in norm


def latest_year_bucket(db: dict) -> dict | None:
    """Bucket dell’anno massimo nel DB (piano conti «corrente» per nuove registrazioni)."""
    years = db.get("years") or []
    if not years:
        return None
    return max(years, key=lambda y: int(y.get("year", 0)))


# Piano categorie/conti per Nuove registrazioni e pagina «Categorie e conti»: anno di riferimento legacy.
PLAN_REFERENCE_YEAR = 2026
# Categorie: modifiche da «Categorie e conti» si applicano a piano e registrazioni da questo anno in poi
# (gli anni pre-2022 restano allineabili all’export JSON legacy; non forzare il piano su quel periodo).
CATEGORY_PLAN_MUTATE_MIN_YEAR = 2022
# Dotazione iniziale (categoria 0) solo nell’anno legacy previsto; altre annate senza dotazione.
LEGACY_DOTAZIONE_YEAR = 1990
_LEGACY_DAT_RECORD_LEN = 121


def year_bucket_for_calendar_year(db: dict, year: int) -> dict | None:
    for yb in db.get("years") or []:
        if int(yb.get("year", 0)) == int(year):
            return yb
    return None


def movement_filter_dataset_bounds(db: dict) -> tuple[date, date, list[int]]:
    """
    Limiti di data e elenco anni per preset/calendario in Movimenti.

    Gli anni uniscono le date effettive delle registrazioni e i ``years[].year`` del DB:
    un anno presente nel piano ma senza record (o con date non leggibili) resta comunque
    selezionabile nel calendario, così non sembra «mancante dall'import».
    """
    records = [r for y in (db.get("years") or []) for r in (y.get("records") or [])]
    parsed: list[date] = []
    for rr in records:
        iso = str(rr.get("date_iso", "")).strip()
        if not iso:
            continue
        try:
            parsed.append(date.fromisoformat(iso[:10]))
        except Exception:
            continue
    bucket_years: list[int] = []
    for yb in db.get("years") or []:
        if not isinstance(yb, dict):
            continue
        try:
            yn = int(yb.get("year", 0))
        except (TypeError, ValueError):
            continue
        if yn > 0:
            bucket_years.append(yn)
    years_union = sorted(set(bucket_years) | {d.year for d in parsed})
    td = date.today()
    if not years_union:
        return td, td, [td.year]
    if parsed:
        return min(parsed), max(parsed), years_union
    lo, hi = min(years_union), max(years_union)
    return date(lo, 1, 1), date(hi, 12, 31), years_union


def chart_clone_source_bucket(db: dict) -> dict | None:
    """Template per clonare piano su nuovi anni: bucket 2026 se presente, altrimenti ultimo anno."""
    yb = year_bucket_for_calendar_year(db, PLAN_REFERENCE_YEAR)
    if yb is not None:
        return yb
    return latest_year_bucket(db)


GIRATA_NOTE_DEFAULT = "Serve a girare importi da un conto all'altro, e non indica una spesa reale"


def plan_conti_reference_bucket(db: dict) -> dict | None:
    """Riferimento UI piano conti: anno 2026 se presente, altrimenti il bucket più completo."""
    y26 = year_bucket_for_calendar_year(db, PLAN_REFERENCE_YEAR)
    if y26 is not None:
        return y26
    years = db.get("years") or []
    if not years:
        return None
    return max(
        years,
        key=lambda y: (
            len([c for c in (y.get("categories") or []) if str(c.get("code", "")) != "0"]),
            len(y.get("accounts") or []),
            int(y.get("year", 0)),
        ),
    )


def plan_conti_category_name_locked(name_raw: str) -> bool:
    """Nome categoria non modificabile: Consumi ordinari, Girata conto/conto."""
    disp = category_display_name(name_raw).strip().lower()
    if disp == "consumi ordinari":
        return True
    nn = " ".join(disp.replace(".", " ").replace("/", " / ").split())
    if "girata conto / conto" in nn or "girata conto conto" in nn:
        return True
    return False


def plan_conti_category_note_locked(name_raw: str) -> bool:
    """Solo Girata: nota predefinita e non editabile da qui."""
    disp = category_display_name(name_raw).strip().lower()
    nn = " ".join(disp.replace(".", " ").replace("/", " / ").split())
    if "girata conto / conto" in nn or "girata conto conto" in nn:
        return True
    return False


def plan_conti_account_is_cassa(name_raw: str) -> bool:
    return category_display_name(name_raw).strip().lower() == "cassa"


def plan_conti_names_have_attinenza(old_raw: str, new_raw: str) -> bool:
    """True se tra vecchio e nuovo esiste almeno una sequenza comune di 4 lettere consecutive."""
    na = category_display_name(old_raw).strip().lower()
    nb = category_display_name(new_raw).strip().lower()
    if not na or not nb:
        return False
    if na == nb:
        return (old_raw or "").strip() != (new_raw or "").strip()
    sa = "".join(ch for ch in na if ch.isalpha())
    sb = "".join(ch for ch in nb if ch.isalpha())
    if len(sa) < 4 or len(sb) < 4:
        return False
    for i in range(0, len(sa) - 3):
        if sa[i : i + 4] in sb:
            return True
    return False


def propagate_category_chart_by_code(
    db: dict,
    code: str,
    name: str,
    note: str | None,
    *,
    min_year_inclusive: int | None = None,
) -> None:
    """Allinea il nome/nota categoria nel piano (tutti gli anni o, con ``min_year_inclusive``, da quell’anno in poi).

    I bucket pre-2022 vanno lasciati coerenti con l’export legacy: da «Categorie e conti» si passa
    ``min_year_inclusive=CATEGORY_PLAN_MUTATE_MIN_YEAR`` così le registrazioni legacy e il piano
    sotto quell’anno non vengono alterati per un rinomina pensata per l’esercizio corrente.
    """
    nt = note if (note or "").strip() else None
    sc = str(code).strip()
    for yb in db.get("years", []) or []:
        if min_year_inclusive is not None:
            try:
                if int(yb.get("year", 0) or 0) < int(min_year_inclusive):
                    continue
            except (TypeError, ValueError):
                continue
        found = False
        for c in yb.get("categories", []) or []:
            if str(c.get("code", "")).strip() == sc:
                c["name"] = name
                c["note"] = nt
                if "category_note" in c:
                    c["category_note"] = nt
                found = True
                break
        if not found:
            yb.setdefault("categories", []).append({"code": sc, "name": name, "note": nt})


def propagate_account_chart_by_code(db: dict, code: str, name: str) -> None:
    sc = str(code).strip()
    for yb in db.get("years", []) or []:
        found = False
        for a in yb.get("accounts", []) or []:
            if str(a.get("code", "")).strip() == sc:
                a["name"] = name
                found = True
                break
        if not found:
            yb.setdefault("accounts", []).append({"code": sc, "name": name})


MAX_ESTRATTI_PDF_STEM_LEN = 120


def estratti_pdf_settings_from_db(db: dict) -> dict:
    """Cartella radice estratti PDF e metadati per la verifica conto (persistiti nel DB cifrato)."""
    ep = db.get("estratti_pdf")
    if not isinstance(ep, dict):
        ep = {}
        db["estratti_pdf"] = ep
    ep.setdefault("root_folder", "")
    return ep


def propagate_account_estratti_pdf_stem_by_code(db: dict, code: str, stem: str) -> None:
    """Nome base file estratto PDF (parte prima di spazio + mese + .pdf) su tutti gli anni, per il codice conto."""
    sc = str(code).strip()
    v = clip_text((stem or "").strip(), MAX_ESTRATTI_PDF_STEM_LEN)
    for yb in db.get("years", []) or []:
        for a in yb.get("accounts", []) or []:
            if str(a.get("code", "")).strip() != sc:
                continue
            if v:
                a["estratti_pdf_stem"] = v
            else:
                a.pop("estratti_pdf_stem", None)
            break


def account_estratti_pdf_stem_for_code(db: dict, acc_code: str) -> str:
    """
    Nome base file estratto PDF per il codice conto, senza suffisso mese/trimestre.
    Usa l’anno di riferimento del piano; se lì manca, cerca lo stesso codice negli altri anni (dati fuori sync).
    """
    sc = str(acc_code).strip()
    yb = year_bucket_for_calendar_year(db, PLAN_REFERENCE_YEAR) or chart_clone_source_bucket(db)
    if yb:
        acc = next((a for a in (yb.get("accounts") or []) if str(a.get("code", "")).strip() == sc), None)
        if acc:
            v = str(acc.get("estratti_pdf_stem") or "").strip()
            if v:
                return v
    for yb2 in db.get("years") or []:
        acc = next((a for a in (yb2.get("accounts") or []) if str(a.get("code", "")).strip() == sc), None)
        if acc:
            v = str(acc.get("estratti_pdf_stem") or "").strip()
            if v:
                return v
    return ""


def _estr_pdf_normalize_name_fragment(s: str) -> str:
    """Spazi Unicode tipo NBSP → spazio normale; solo trim iniziale/finale (non altera spazi centrali)."""
    t = (s or "").replace("\u00a0", " ").replace("\u202f", " ").replace("\u2007", " ")
    return t.strip()


def parse_estratto_pdf_suffix_for_stem(pdf_filename: str, stem: str) -> tuple[str, int] | None:
    """
    Se ``pdf_filename`` è ``<stem>`` + spazi (anche Unicode) + suffisso + ``.pdf``, restituisce (``'M'``, mese 1–12)
    oppure (``'T'``, trimestre 1–4). Il confronto con ``stem`` ignora maiuscole/minuscole (file system macOS).
    """
    if not pdf_filename.lower().endswith(".pdf"):
        return None
    stem_n = _estr_pdf_normalize_name_fragment(stem)
    if not stem_n:
        return None
    base_n = _estr_pdf_normalize_name_fragment(pdf_filename[:-4])
    try:
        m = re.fullmatch(
            re.escape(stem_n) + r"\s*(\d{2}|[tT][1-4])",
            base_n,
            flags=re.IGNORECASE,
        )
    except re.error:
        return None
    if not m:
        return None
    suf = m.group(1)
    if len(suf) == 2 and suf.isdigit():
        v = int(suf)
        if 1 <= v <= 12:
            return ("M", v)
        return None
    if len(suf) == 2 and suf[0].upper() == "T" and suf[1] in "1234":
        return ("T", int(suf[1]))
    return None


def pick_estratto_pdf_in_folder(
    folder: Path,
    stem: str,
    dco: date,
    *,
    allow_next_month: bool = False,
) -> Path | None:
    """
    Tra i PDF **direttamente** nella cartella ``folder`` che rispettano il nome base ``stem``, sceglie quello con **suffisso più alto**
    tra quelli ancora compatibili con la data di chiusura: mese ``MM`` con ``MM <= mese(chiusura)``, oppure — se non
    ce n’è nessuno — trimestre ``Tn`` con ``n <= trimestre(chiusura)``. Per le carte può essere ammesso anche il
    mese successivo alla chiusura, perché alcuni estratti sono nominati col mese di emissione/pagamento.
    Stessa logica di lettura del file scelto.
    """
    cut_m = min(12, dco.month + (1 if allow_next_month else 0))
    cut_q = (dco.month - 1) // 3 + 1
    monthly: list[tuple[int, Path]] = []
    quarterly: list[tuple[int, Path]] = []
    try:
        for p in folder.iterdir():
            if not p.is_file():
                continue
            if p.suffix.lower() != ".pdf":
                continue
            parsed = parse_estratto_pdf_suffix_for_stem(p.name, stem)
            if parsed is None:
                continue
            kind, val = parsed
            if kind == "M":
                monthly.append((val, p))
            else:
                quarterly.append((val, p))
    except OSError:
        return None
    eligible_m = [(m, path) for m, path in monthly if m <= cut_m]
    if eligible_m:
        return max(eligible_m, key=lambda t: t[0])[1]
    eligible_t = [(q, path) for q, path in quarterly if q <= cut_q]
    if eligible_t:
        return max(eligible_t, key=lambda t: t[0])[1]
    return None


def resolve_estratto_pdf_for_account(
    db: dict, acc_code: str, cutoff_raw_ggmmyyyy: str
) -> tuple[Path | None, str]:
    """
    Cerca il PDF nella **sola** cartella radice impostata nella Verifica automatica (nessuna sottocartella anno): file
    ``<nomebase> <MM>.pdf`` / ``<nomebase><MM>.pdf`` o trimestre ``Tn``, con il **suffisso più alto** tra quelli
    presenti e ancora compatibili con la data di chiusura. Restituisce ``(percorso, testo_diagnostica)``.
    """
    lines: list[str] = []

    def ln(s: str) -> None:
        lines.append(s)

    root_raw = (estratti_pdf_settings_from_db(db).get("root_folder") or "").strip()
    ln(f"Cartella radice (Verifica automatica), valore in database: {root_raw or '(vuoto)'}")
    if not root_raw:
        ln("Errore: impostare la cartella nella Verifica automatica e premere «Conferma».")
        return None, "\n".join(lines)

    root = Path(root_raw).expanduser()
    try:
        ln(f"Percorso assoluto usato per la ricerca: {root.resolve()}")
    except Exception:
        ln(f"Percorso usato per la ricerca: {root}")

    if not root.is_dir():
        ln("Errore: non è una cartella accessibile.")
        return None, "\n".join(lines)

    stem = account_estratti_pdf_stem_for_code(db, acc_code)
    ln(f"Nome base file (Conti): «{stem}»" if stem else "Nome base file (Conti): (mancante)")
    if not stem:
        ln("Errore: compilare il nome base nella pagina Conti per questo conto.")
        return None, "\n".join(lines)

    try:
        iso = parse_italian_ddmmyyyy_to_iso((cutoff_raw_ggmmyyyy or "").strip())
        if not iso:
            ln("Errore: data di chiusura non valida.")
            return None, "\n".join(lines)
        dco = date.fromisoformat(iso)
    except Exception:
        ln("Errore: data di chiusura non interpretabile.")
        return None, "\n".join(lines)

    allow_next_month = account_is_credit_card_by_code(db, acc_code)
    month_limit = min(12, dco.month + (1 if allow_next_month else 0))
    extra_month_note = " (conto carta: ammesso anche il mese successivo)" if allow_next_month else ""
    ln(
        f"Criterio: tra i .pdf con nome «{stem}» + spazio opzionale + (01…12 o T1…T4), suffisso massimo "
        f"con mese ≤ {month_limit}{extra_month_note} (oppure trimestre ≤ {(dco.month - 1) // 3 + 1})."
    )
    picked = pick_estratto_pdf_in_folder(root, stem, dco, allow_next_month=allow_next_month)
    if picked is not None and picked.is_file():
        try:
            ln(f"File selezionato: {picked.resolve()}")
        except Exception:
            ln(f"File selezionato: {picked}")
        return picked, "\n".join(lines)

    ln("Esito: nessun PDF idoneo trovato con nome base e suffisso compatibile.")
    try:
        pdf_names = sorted(
            p.name for p in root.iterdir() if p.is_file() and p.suffix.lower() == ".pdf"
        )
        if pdf_names:
            head = pdf_names[:30]
            tail = " …" if len(pdf_names) > 30 else ""
            ln(f".pdf presenti in cartella ({len(pdf_names)}): {', '.join(head)}{tail}")
        else:
            ln("Nessun file .pdf in questa cartella.")
    except OSError as exc:
        ln(f"Impossibile elencare i file: {exc}")
    return None, "\n".join(lines)


def _ver_account_expects_auto_estratto_pdf(db: dict, acc_code: str) -> bool:
    """True se in Conti è impostato il nome base PDF e in Opzioni la cartella radice (ricerca automatica prevista)."""
    if not (account_estratti_pdf_stem_for_code(db, acc_code) or "").strip():
        return False
    return bool((estratti_pdf_settings_from_db(db).get("root_folder") or "").strip())


