    correzione_forza_revealed: list[bool] = [False]
    _correzione_bar_prev_sel_key: list[str | None] = [None]

    def refresh_correction_bar() -> None:
        """Aggiorna la barra in base alla riga selezionata. Il tasto Modifica non viene tolto
        se si passa da una registrazione modificabile a un'altra: resta visibile e l'azione usa
        sempre la selezione corrente (vedi on_modifica_reg_click)."""
        sel = mov_tree.selection()
        key = sel[0] if sel else None
        if key != _correzione_bar_prev_sel_key[0]:
            correzione_forza_revealed[0] = False
        _correzione_bar_prev_sel_key[0] = key

        want_forza = False
        want_elimina = False
        want_msg = False
        want_modifica = False
        category_only_legacy = False
        has_verifica_flags = False
        forza_ok_recency = False
        msg_text = (
            f"Registrazione non modificabile: data precedente al {RECORD_MOD_DELETE_CUTOFF_DATE:%d/%m/%Y}."
        )

        if sel:
            sk = sel[0]
            pair = find_record_year_and_ref(cur_db(), sk)
            if pair:
                _yd, rec = pair
                if record_has_account_verification_flags(rec):
                    has_verifica_flags = True
                forza_ok_recency = record_is_within_forza_verifica_recency(rec)
                if record_touches_frozen_account(cur_db(), rec):
                    want_msg = True
                    msg_text = "Conto congelato: la registrazione non è modificabile né eliminabile."
                elif not record_is_within_recent_mod_delete_window(rec):
                    if record_is_before_2022(rec) and not is_giroconto_record(rec):
                        want_modifica = True
                        category_only_legacy = True
                    else:
                        want_msg = True
                elif record_is_before_2022(rec):
                    want_modifica = True
                    category_only_legacy = True
                else:
                    want_modifica = True
                    if record_contains_any_asterisk(rec):
                        want_msg = True
                        msg_text = "Registrazione verificata non cancellabile."

                if category_only_legacy:
                    want_msg = True
                    msg_text = "Registrazione storica: modificabile solo la categoria."

        want_forza = (
            has_verifica_flags
            and want_modifica
            and forza_ok_recency
            and correzione_forza_revealed[0]
        )
        want_elimina = want_modifica and (not want_forza) and (not category_only_legacy)
        if sel:
            pair = find_record_year_and_ref(cur_db(), sel[0])
            if pair:
                _yd, rec = pair
                if record_contains_any_asterisk(rec):
                    want_elimina = False

        col = 1
        if want_msg:
            lbl_correzione_msg.configure(text=msg_text)
            lbl_correzione_msg.grid(row=0, column=col, sticky="w", padx=(0, 12))
            col += 1
        else:
            lbl_correzione_msg.grid_remove()

        if want_modifica:
            btn_modifica_reg.grid(row=0, column=col, sticky="w", padx=(0, 12))
            col += 1
        else:
            btn_modifica_reg.grid_remove()

        if want_forza:
            btn_forza_verifica.grid(row=0, column=col, sticky="w", padx=(0, 12))
            col += 1
        else:
            btn_forza_verifica.grid_remove()
        if want_elimina:
            btn_elimina_reg.grid(row=0, column=col, sticky="w", padx=(0, 12))
        else:
            btn_elimina_reg.grid_remove()

        sp_txt = (saldo_parziale_categoria_ricerca_text[0] or "").strip()
        if sp_txt:
            try:
                correzione_row.columnconfigure(98, weight=1)
            except tk.TclError:
                pass
            lbl_saldo_parziale_categoria.configure(text=sp_txt)
            lbl_saldo_parziale_categoria.grid(row=0, column=99, sticky="e", padx=(4, 0))
        else:
            try:
                correzione_row.columnconfigure(98, weight=0)
            except tk.TclError:
                pass
            lbl_saldo_parziale_categoria.grid_remove()

    def persist_db_after_edit(
        reselect_key: str | None,
        *,
        refresh_movements: bool = True,
        ensure_reselected_visible: bool = False,
    ) -> None:
        try:
            primary_target = Path(data_file_var.get()).expanduser().resolve()
        except Exception:
            primary_target = Path(data_file_var.get())
        try:
            key_target = Path(key_file_var.get()).expanduser().resolve()
        except Exception:
            key_target = Path(key_file_var.get())
        try:
            save_encrypted_db_dual(
                cur_db(),
                primary_target,
                key_target,
            )
            # Correzioni da «Movimenti / Modifica registrazione»:
            # oltre al path operativo in Opzioni, riallinea sempre anche il file canonico
            # per-email (quello usato dalla app light), se diverso.
            em = (session_holder[0].user_email or "").strip().lower()
            if em:
                canonical_target = per_user_encrypted_db_path(em).resolve()
                current_target = primary_target
                if canonical_target != current_target:
                    save_encrypted_db_dual(
                        cur_db(),
                        canonical_target,
                        key_target,
                    )
        except Exception as exc:
            messagebox.showerror("Salvataggio", str(exc))
            return
        if refresh_movements:
            fallback_idx: int | None = None
            if reselect_key:
                try:
                    _ch_now = list(mov_tree.get_children())
                    if reselect_key in _ch_now:
                        fallback_idx = _ch_now.index(reselect_key)
                except Exception:
                    fallback_idx = None
            populate_movements_trees(
                reselect_stable_key=reselect_key,
                preserve_scroll=True,
                reselect_fallback_index=fallback_idx,
                ensure_reselected_visible=ensure_reselected_visible,
            )
            refresh_balance_footer()
        vrf = ver_results_after_persist_cb[0]
        if vrf is not None:
            try:
                vrf()
            except Exception:
                pass
        fn_bud = _budget_on_tab_enter_fn[0]
        if fn_bud is not None:
            try:
                fn_bud()
            except Exception:
                pass

    def open_edit_date(stable_key: str) -> None:
        pair = find_record_year_and_ref(cur_db(), stable_key)
        if not pair:
            return
        _yd, rec = pair
        if record_touches_frozen_account(cur_db(), rec):
            messagebox.showwarning(
                "Movimenti",
                "La registrazione coinvolge un conto congelato: non è modificabile.",
                parent=root,
            )
            return
        if not record_is_within_edit_age(rec):
            return
        year_n = int(rec.get("year", 0))
        top = _mov_edit_new_dialog("Modifica data")
        frm = ttk.Frame(top, padding=12)
        frm.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frm, text="Data (gg/mm/aaaa):").grid(row=0, column=0, sticky="w")
        v = tk.StringVar(value=to_italian_date(str(rec.get("date_iso", ""))))
        ttk.Entry(frm, textvariable=v, width=14).grid(row=0, column=1, sticky="w", padx=(8, 0))

        def on_ok() -> None:
            iso = parse_italian_ddmmyyyy_to_iso(v.get())
            if not iso:
                messagebox.showerror("Data", "Formato non valido (gg/mm/aaaa).", parent=top)
                return
            try:
                dnew = date.fromisoformat(iso)
            except Exception:
                messagebox.showerror("Data", "Data non valida.", parent=top)
                return
            if dnew.year != year_n:
                messagebox.showerror(
                    "Data",
                    f"La data deve restare nell'anno contabile del record ({year_n}).",
                    parent=top,
                )
                return
            cutoff = date_minus_calendar_years(date.today(), 5)
            if dnew < cutoff:
                messagebox.showerror(
                    "Data",
                    "La data risulta oltre il limite dei 5 anni consentiti per la modifica.",
                    parent=top,
                )
                return
            # Ricerca per data: la nuova data non deve uscire dall'intervallo applicato (stessi limiti della griglia).
            if filter_order_applied_var.get() == "date":
                fmin = _parse_iso_to_date(date_from_applied_var.get())
                fmax = _parse_iso_to_date(date_to_applied_var.get())
                if fmin and fmax:
                    if fmin > fmax:
                        fmin, fmax = fmax, fmin
                    if filter_future_applied_var.get() == "exclude":
                        today = date.today()
                        if fmax > today:
                            fmax = today
                        if fmin > today:
                            fmin = today
                    if dnew < fmin or dnew > fmax:
                        messagebox.showerror(
                            "Data",
                            "La nuova data deve restare nell'intervallo della ricerca attuale "
                            f"({to_italian_date(fmin.isoformat())} – {to_italian_date(fmax.isoformat())}).",
                            parent=top,
                        )
                        return
            rec["date_iso"] = iso
            top.destroy()
            persist_db_after_edit(stable_key, ensure_reselected_visible=True)

        bf = ttk.Frame(frm)
        bf.grid(row=1, column=0, columnspan=2, pady=(12, 0))
        ttk.Button(bf, text="Annulla", command=top.destroy).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(bf, text="Salva", command=on_ok).pack(side=tk.LEFT)

    def open_edit_category(stable_key: str) -> None:
        pair = find_record_year_and_ref(cur_db(), stable_key)
        if not pair:
            return
        _yd, rec = pair
        if record_touches_frozen_account(cur_db(), rec):
            messagebox.showwarning(
                "Movimenti",
                "La registrazione coinvolge un conto congelato: non è modificabile.",
                parent=root,
            )
            return
        category_only_legacy = record_is_before_2022(rec)
        if category_only_legacy and is_giroconto_record(rec):
            messagebox.showwarning(
                "Categoria",
                "Le registrazioni storiche «GIRATA CONTO/CONTO» non possono essere riclassificate.",
                parent=root,
            )
            return
        if not record_is_within_edit_age(rec) and not category_only_legacy:
            return
        py = record_category_plan_year(rec, _yd)
        year_categories = year_categories_map(cur_db()).get(py, []) or []
        choices: list[tuple[str, str]] = []
        disp_to_raw: dict[str, str] = {}

        def _norm_cat_mov_label(s: str) -> str:
            return " ".join((s or "").strip().lower().replace(".", " ").replace("/", " / ").split())

        def _is_girata_display_name(s: str) -> bool:
            n = _norm_cat_mov_label(s)
            return ("girata conto / conto" in n) or ("girata conto conto" in n)

        for i, c in enumerate(year_categories):
            code = str(c.get("code", str(i)))
            if code == "0":
                continue
            if is_hidden_dotazione_category_name(str(c.get("name", ""))):
                continue
            disp = category_display_name(c.get("name", ""))
            if category_only_legacy and _is_girata_display_name(disp):
                continue
            raw_nm = str(c.get("name", "") or "")
            choices.append((disp, code))
            disp_to_raw.setdefault(disp, raw_nm)

        if not choices:
            messagebox.showerror("Categoria", "Nessuna categoria disponibile per questo anno.")
            return

        consumi_disp = next((d for d, _c in choices if _norm_cat_mov_label(d) == "consumi ordinari"), None)
        girata_disp = None if category_only_legacy else next((d for d, _c in choices if _is_girata_display_name(d)), None)
        locked_heads = [x for x in (consumi_disp, girata_disp) if x]
        others = [(d, c) for d, c in choices if d not in locked_heads]
        others.sort(key=lambda it: it[0].lower())
        values_list = locked_heads + [d for d, _c in others]
        top = _mov_edit_new_dialog("Modifica categoria")
        frm = ttk.Frame(top, padding=12)
        frm.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frm, text="Categoria:").grid(row=0, column=0, sticky="w")
        cb = ttk.Combobox(frm, state="readonly", width=32, values=values_list)
        cc = str(rec.get("category_code", ""))
        initial_disp = next((d for d, code in choices if code == cc), choices[0][0])

        def _edit_cat_skip_letter_jump(disp: str) -> bool:
            """Consumi ordinari e Girata: non preselezionabili con la lettera; restano selezionabili col mouse."""
            raw = disp_to_raw.get(disp, "")
            return plan_conti_category_name_locked(raw)

        cb.set(initial_disp)
        try:
            cb.current(values_list.index(initial_disp))
        except ValueError:
            pass
        cb.grid(row=0, column=1, sticky="w", padx=(8, 0))

        def _jump_first_letter(letter: str) -> bool:
            for idx, nm in enumerate(values_list):
                if not nm or str(nm[0]).lower() != letter:
                    continue
                if _edit_cat_skip_letter_jump(nm):
                    continue
                cb.set(nm)
                try:
                    cb.current(idx)
                except ValueError:
                    pass
                _ttk_combobox_sync_open_popdown_selection(cb, idx)
                return True
            return False

        _combo_cleanup = bind_ttk_combobox_letter_jump_with_popdown(cb, on_letter=_jump_first_letter)

        def _on_cat_dialog_destroy(e: tk.Event) -> None:
            if getattr(e, "widget", None) is top:
                _combo_cleanup()

        top.bind("<Destroy>", _on_cat_dialog_destroy, add="+")

        def on_ok() -> None:
            picked = cb.get()
            code = next((code for d, code in choices if d == picked), None)
            if code is None:
                messagebox.showerror("Categoria", "Selezione non valida.", parent=top)
                return
            if category_only_legacy and _is_girata_display_name(picked):
                messagebox.showwarning(
                    "Categoria",
                    "Non è consentito applicare «GIRATA CONTO/CONTO» a una registrazione storica.",
                    parent=top,
                )
                return
            sync_record_category_from_plan(rec, year_categories, code)
            top.destroy()
            persist_db_after_edit(stable_key, ensure_reselected_visible=True)

        bf = ttk.Frame(frm)
        bf.grid(row=1, column=0, columnspan=2, pady=(12, 0))
        ttk.Button(bf, text="Annulla", command=top.destroy).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(bf, text="Salva", command=on_ok).pack(side=tk.LEFT)

    def _mov_edit_account_menu_pick_to_plan_index(accounts: list, picked: str) -> int | None:
        p = (picked or "").strip()
        for i, a in enumerate(accounts):
            if str(a.get("name", "") or "").strip() == p:
                return i
        return None

    def _mov_edit_account_preselect_menu_label(
        rec: dict, accounts: list, names: list[str], *, which: str
    ) -> str:
        """Allinea la combo al conto reale: nome in registrazione / piano conti, non all'indice nella lista ordinata."""
        nk = "account_primary_name" if which == "primary" else "account_secondary_name"
        ck = "account_primary_code" if which == "primary" else "account_secondary_code"
        nm = str(rec.get(nk) or "").strip()
        if nm and nm in names:
            return nm
        code = str(rec.get(ck, "")).strip()
        if code.isdigit():
            aidx = int(code) - 1
            if 0 <= aidx < len(accounts):
                plan_nm = str(accounts[aidx].get("name", "") or "").strip()
                if plan_nm in names:
                    return plan_nm
        return names[0] if names else ""

