    def _set_movimenti_elenco_expanded(want: bool) -> None:
        if bool(_movimenti_elenco_expanded[0]) == bool(want):
            return
        for _lj in (_mov_tree_vline_after, _mov_hdr_vline_after):
            _jid = _lj[0]
            if _jid is not None:
                try:
                    root.after_cancel(_jid)
                except (tk.TclError, ValueError, TypeError):
                    pass
                _lj[0] = None
        _movimenti_elenco_expanded[0] = bool(want)
        if want:
            balance_footer.grid_remove()
            filters_row.pack_forget()
            filters_search_row.pack_forget()
            filters_text_row.pack_forget()
            records_frame.pack(fill=tk.BOTH, expand=True)
            try:
                btn_espandi_elenco_mov.pack_forget()
            except tk.TclError:
                pass
            try:
                btn_mov_griglia_ripristina.pack(side=tk.LEFT, padx=(0, 10), before=btn_stampa_ricerca)
            except tk.TclError:
                pass

            def _post_expand_layout() -> None:
                if not _movimenti_elenco_expanded[0]:
                    return
                try:
                    movimenti_body.update_idletasks()
                    records_frame.update_idletasks()
                    _position_mov_tree_vlines()
                    _position_mov_hdr_vlines()
                except Exception:
                    pass

            root.after_idle(_post_expand_layout)
        else:
            try:
                btn_mov_griglia_ripristina.pack_forget()
            except tk.TclError:
                pass
            movimenti_main_stack.rowconfigure(0, weight=1, minsize=0)
            movimenti_main_stack.rowconfigure(1, weight=0, minsize=0)
            filters_row.pack(fill=tk.X, pady=(0, 2), before=records_frame)
            filters_search_row.pack(fill=tk.X, pady=(0, 4), before=records_frame)
            filters_text_row.pack(fill=tk.X, pady=(0, 6), before=records_frame)
            balance_footer.grid(row=1, column=0, sticky="ew")
            records_frame.pack(fill=tk.BOTH, expand=True)
            try:
                refresh_date_controls_visibility()
            except Exception:
                pass
            try:
                btn_espandi_elenco_mov.pack(side=tk.LEFT, padx=(0, 8), before=btn_stampa_ricerca)
            except tk.TclError:
                pass
        root.update_idletasks()
        try:
            _position_mov_tree_vlines()
            _position_mov_hdr_vlines()
        except Exception:
            pass
        try:
            refresh_correction_bar()
        except Exception:
            pass

    def _on_espandi_elenco_mov_click(_event: tk.Event | None = None) -> None:
        _set_movimenti_elenco_expanded(True)

    def _on_mov_griglia_ripristina_click(_event: tk.Event | None = None) -> None:
        _set_movimenti_elenco_expanded(False)

    btn_espandi_elenco_mov.bind("<Button-1>", _on_espandi_elenco_mov_click)
    btn_mov_griglia_ripristina.bind("<Button-1>", _on_mov_griglia_ripristina_click)

    pending_movement_rows: list[
        tuple[str, str, tuple[object, ...], str, str, str, str]
    ] = []
    movements_population_seq = 0
    _movements_dirty: list[bool] = [False]

    def _build_movement_search_filter_state() -> dict[str, object]:
        q_cat_raw = text_category_applied_var.get().strip()
        q_acc_raw = text_account_applied_var.get().strip()
        q_cat = "" if q_cat_raw in ("", _ALL_CATEGORIES_LABEL) else q_cat_raw.lower()
        q_acc = "" if q_acc_raw in ("", _ALL_ACCOUNTS_LABEL) else q_acc_raw.lower()
        q_chq = (text_cheque_applied_var.get() or "").lower()
        q_note = (text_note_applied_var.get() or "").casefold()
        q_amt_raw = (text_amount_applied_var.get() or "").strip()
        q_amt: Decimal | None = None
        if q_amt_raw:
            try:
                q_amt = normalize_euro_input(q_amt_raw)
            except Exception:
                q_amt = None
        reg_from_n: int | None = None
        reg_to_n: int | None = None
        if filter_order_applied_var.get() == "registration":
            try:
                reg_from_n = int(str(reg_from_applied_var.get()).strip())
                reg_to_n = int(str(reg_to_applied_var.get()).strip())
            except Exception:
                reg_from_n = None
                reg_to_n = None
        q_cat_sub = (text_aggregate_category_applied_var.get() or "").strip().lower()
        return {
            "mode": filter_order_applied_var.get(),
            "q_cat": q_cat,
            "q_cat_sub": q_cat_sub,
            "q_acc": q_acc,
            "q_chq": q_chq,
            "q_note": q_note,
            "q_amt": q_amt,
            "reg_from_n": reg_from_n,
            "reg_to_n": reg_to_n,
        }

    def _record_passes_movement_search_filters(
        r: dict,
        st: dict[str, object],
        reg_seq_map: dict,
        accounts_by_year: dict,
        categories_by_year: dict,
    ) -> tuple[bool, str, str, str, str, str]:
        """True se la rispetta i filtri applicati; restituisce anche nomi conti/categoria per la griglia."""
        if not show_record_in_movements_grid(r):
            return (False, "", "", "", "", "")
        year = r.get("year")
        year_accounts = accounts_by_year.get(year, [])
        year_categories = categories_by_year.get(year, [])
        account_1_name = account_name_for_record(r, year_accounts, "primary")
        account_2_name = account_name_for_record(r, year_accounts, "secondary")
        acc1_norm = (account_1_name or "").strip().lower()
        acc2_norm = (account_2_name or "").strip().lower()
        category_name = category_name_for_record(r, year_categories)
        stars_1 = r.get("account_primary_flags", "")
        stars_2 = r.get("account_secondary_flags", "")
        mode = st["mode"]
        q_cat = str(st["q_cat"] or "")
        q_cat_sub = str(st.get("q_cat_sub") or "")
        q_acc = str(st["q_acc"] or "")
        q_chq = str(st["q_chq"] or "")
        q_note = str(st["q_note"] or "")
        q_amt = st.get("q_amt")
        if mode == "date":
            if q_cat_sub:
                if q_cat_sub not in (category_name or "").lower():
                    return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            elif q_cat and q_cat != (category_name or "").lower():
                return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            if q_acc and q_acc != acc1_norm and q_acc != acc2_norm:
                return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            if q_amt is not None:
                try:
                    if to_decimal(r.get("amount_eur", "0")) != q_amt:
                        return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
                except Exception:
                    return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            if q_chq and q_chq not in str(r.get("cheque") or "").lower():
                return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            if q_note and q_note not in str(r.get("note") or "").casefold():
                return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
        elif mode == "registration":
            nreg = reg_seq_map[record_legacy_stable_key(r)]
            reg_from_n = st.get("reg_from_n")
            reg_to_n = st.get("reg_to_n")
            if reg_from_n is not None and reg_to_n is not None:
                if filter_direction_applied_var.get() == "backward":
                    if nreg > reg_from_n or nreg < reg_to_n:
                        return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
                else:
                    if nreg < reg_from_n or nreg > reg_to_n:
                        return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            if q_cat_sub:
                if q_cat_sub not in (category_name or "").lower():
                    return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            elif q_cat and q_cat != (category_name or "").lower():
                return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            if q_acc and q_acc != acc1_norm and q_acc != acc2_norm:
                return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
            if q_note and q_note not in str(r.get("note") or "").casefold():
                return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
        else:
            return (False, category_name, account_1_name, stars_1, account_2_name, stars_2)
        return (True, category_name, account_1_name, stars_1, account_2_name, stars_2)

    def _movement_rows_from_pool(
        pool: list[dict],
        reg_seq_map: dict,
        accounts_by_year: dict,
        categories_by_year: dict,
    ) -> list[tuple[str, str, tuple[object, ...], str, str, str, str]]:
        """Stessa logica della griglia: (iid, reg#, mov_vals×7, importo, tag colore, nota, stripe)."""
        st = _build_movement_search_filter_state()
        row_i = 0
        out: list[tuple[str, str, tuple[object, ...], str, str, str, str]] = []
        for r in pool:
            ok, category_name, account_1_name, stars_1, account_2_name, stars_2 = (
                _record_passes_movement_search_filters(r, st, reg_seq_map, accounts_by_year, categories_by_year)
            )
            if not ok:
                continue
            amount_text, amount_tag = format_amount_for_output(r)
            stripe = f"stripe{row_i % 2}"
            rid = record_legacy_stable_key(r)
            reg_text = str(reg_seq_map[rid])
            mov_vals = (
                to_italian_date(r["date_iso"]),
                category_name,
                account_1_name,
                stars_1,
                account_2_name,
                stars_2,
                r.get("cheque") or "",
            )
            out.append((rid, reg_text, mov_vals, amount_text, amount_tag, r.get("note") or "", stripe))
            row_i += 1
        return out

    def _recompute_saldo_parziale_categoria_ricerca_text(
        pool: list[dict],
        reg_seq_map: dict,
        accounts_by_year: dict,
        categories_by_year: dict,
    ) -> None:
        agg_raw = (text_aggregate_category_applied_var.get() or "").strip()
        cat_raw = (text_category_applied_var.get() or "").strip()
        if not agg_raw and (not cat_raw or cat_raw == _ALL_CATEGORIES_LABEL):
            saldo_parziale_categoria_ricerca_text[0] = ""
            return
        st = _build_movement_search_filter_state()
        tot = Decimal("0")
        for r in pool:
            ok, *_rest = _record_passes_movement_search_filters(
                r, st, reg_seq_map, accounts_by_year, categories_by_year
            )
            if not ok:
                continue
            try:
                tot += to_decimal(r.get("amount_eur", "0"))
            except Exception:
                pass
        if filter_order_applied_var.get() == "date":
            df = (date_from_applied_var.get() or "").strip()
            dt = (date_to_applied_var.get() or "").strip()
        else:
            df, dt = _scope_dates_for_registration(reg_preset_applied_var.get())
        if not df or not dt:
            saldo_parziale_categoria_ricerca_text[0] = ""
            return
        di = to_italian_date(df)
        al = to_italian_date(dt)
        amt_txt = format_saldo_cell("E", tot)
        if agg_raw:
            saldo_parziale_categoria_ricerca_text[0] = (
                f"Saldo parziale delle categorie il cui nome contiene «{agg_raw}» dal {di} al {al}: {amt_txt}"
            )
            return
        saldo_parziale_categoria_ricerca_text[0] = (
            f"Saldo parziale della categoria «{cat_raw}» dal {di} al {al}: {amt_txt}"
        )

    def populate_movements_trees(
        reselect_stable_key: str | None = None,
        *,
        preserve_scroll: bool = False,
        reselect_fallback_index: int | None = None,
        ensure_reselected_visible: bool = False,
    ) -> None:
        nonlocal movements_population_seq
        movements_population_seq += 1
        token_local = movements_population_seq
        reselect_key = reselect_stable_key
        saved_yview_top: float | None = None
        if preserve_scroll:
            try:
                saved_yview_top = float(mov_tree.yview()[0])
            except Exception:
                saved_yview_top = None
        try:
            refresh_search_title()
        except Exception:
            pass
        # Nascondi eventuale messaggio "no risultati"
        try:
            no_results_block.grid_remove()
        except Exception:
            pass
        _clear_selection(mov_tree)
        _clear_selection(amt_tree)
        _clear_selection(note_tree)
        for iid in mov_tree.get_children():
            mov_tree.delete(iid)
        for iid in amt_tree.get_children():
            amt_tree.delete(iid)
        for iid in note_tree.get_children():
            note_tree.delete(iid)
        if not preserve_scroll:
            scroll_movements_grid_to_top()
        d = cur_db()
        accounts_by_year = year_accounts_map(d)
        categories_by_year = year_categories_map(d)
        records = [r for y in d["years"] for r in y["records"]]
        records.sort(key=record_merge_sort_key)
        reg_seq_map = unified_registration_sequence_map(records)

        # Bounds date del dataset (servono per preset e per calendario).
        nonlocal _dataset_min_date, _dataset_max_date, _dataset_years_with_records
        _dataset_min_date, _dataset_max_date, _dataset_years_with_records = movement_filter_dataset_bounds(d)

        # Se la UI date è già stata creata, riallinea i campi preset su nuovi bounds (es. dopo import legacy).
        try:
            refresh_date_year_menu()
            refresh_date_preview_from_modes()
        except NameError:
            pass

        pool = filter_and_sort_movements_for_grid(
            records,
            reg_seq_map,
            order_by_date=filter_order_applied_var.get() == "date",
            exclude_future_dates=filter_future_applied_var.get() == "exclude",
            backward=filter_direction_applied_var.get() == "backward",
            date_from_iso=(
                date_from_applied_var.get()
                if filter_order_applied_var.get() == "date"
                else (_scope_dates_for_registration(reg_preset_applied_var.get())[0] if filter_order_applied_var.get() == "registration" else None)
            ),
            date_to_iso=(
                date_to_applied_var.get()
                if filter_order_applied_var.get() == "date"
                else (_scope_dates_for_registration(reg_preset_applied_var.get())[1] if filter_order_applied_var.get() == "registration" else None)
            ),
        )
        pending_movement_rows.clear()
        pending_movement_rows.extend(
            _movement_rows_from_pool(pool, reg_seq_map, accounts_by_year, categories_by_year)
        )
        try:
            _recompute_saldo_parziale_categoria_ricerca_text(
                pool, reg_seq_map, accounts_by_year, categories_by_year
            )
        except Exception:
            saldo_parziale_categoria_ricerca_text[0] = ""
        try:
            refresh_correction_bar()
        except Exception:
            pass

        def flush_movement_batch(start: int) -> None:
            # Evita race condition: se nel frattempo viene lanciato un nuovo populate,
            # i batch vecchi non devono inserire nel Treeview corrente.
            if token_local != movements_population_seq:
                return
            end = min(start + MOVEMENTS_INSERT_BATCH, len(pending_movement_rows))
            for i in range(start, end):
                rid, reg_text, mov_vals, amount_text, amount_tag, note_text, stripe = pending_movement_rows[i]
                mov_tree.insert(
                    "",
                    tk.END,
                    iid=rid,
                    values=("", reg_text) + mov_vals,
                    tags=(stripe,),
                )
                amt_tree.insert("", tk.END, iid=rid, values=(amount_text,), tags=(amount_tag, stripe))
                note_tree.insert("", tk.END, iid=rid, values=(note_text,), tags=(stripe,))
            if end < len(pending_movement_rows):
                root.after(1, lambda s=end: flush_movement_batch(s))
            else:
                # Risultati presenti: assicurati che intestazione e griglia siano visibili.
                try:
                    no_results_block.grid_remove()
                except Exception:
                    pass
                try:
                    mov_records_header_row.grid()
                    mov_tree.grid()
                    sep_1.grid()
                    amt_tree.grid()
                    sep_2.grid()
                    note_tree.grid()
                    yscroll.grid()
                except Exception:
                    pass

                def _restore_scroll_or_top() -> None:
                    if token_local != movements_population_seq:
                        return
                    if preserve_scroll and saved_yview_top is not None:
                        try:
                            mov_tree.yview_moveto(saved_yview_top)
                        except Exception:
                            pass
                    else:
                        scroll_movements_grid_to_top()

                root.after_idle(_restore_scroll_or_top)

                def _reselect_and_bar() -> None:
                    if token_local != movements_population_seq:
                        return
                    picked_iid: str | None = None
                    if reselect_key:
                        try:
                            if mov_tree.exists(reselect_key):
                                mov_tree.selection_set(reselect_key)
                                picked_iid = reselect_key
                        except Exception:
                            pass
                    if picked_iid is None and reselect_fallback_index is not None:
                        try:
                            ch = list(mov_tree.get_children())
                            if ch:
                                idx = max(0, min(int(reselect_fallback_index), len(ch) - 1))
                                picked_iid = str(ch[idx])
                                mov_tree.selection_set(picked_iid)
                        except Exception:
                            picked_iid = None
                    if picked_iid is not None:
                        try:
                            if ensure_reselected_visible or (not preserve_scroll):
                                mov_tree.see(picked_iid)
                        except Exception:
                            pass
                    try:
                        refresh_correction_bar()
                    except Exception:
                        pass

                root.after_idle(_reselect_and_bar)

        if pending_movement_rows:
            # Mostra griglia/intestazione (se erano state nascoste per "nessun risultato").
            try:
                no_results_block.grid_remove()
            except Exception:
                pass
            try:
                mov_records_header_row.grid()
                mov_tree.grid()
                sep_1.grid()
                amt_tree.grid()
                sep_2.grid()
                note_tree.grid()
                yscroll.grid()
            except Exception:
                pass
            root.after(0, lambda: flush_movement_batch(0))
        else:
            # Nessun risultato: pannello a tutta la riga elenco (sopra i separatori colore intestazione).
            try:
                mov_records_header_row.grid_remove()
                mov_tree.grid_remove()
                sep_1.grid_remove()
                amt_tree.grid_remove()
                sep_2.grid_remove()
                note_tree.grid_remove()
                yscroll.grid_remove()
            except Exception:
                pass
            try:
                no_results_block.grid(row=3, column=0, columnspan=6, sticky="nsew")
                no_results_block.lift()
            except Exception:
                pass

