    def _stat_categories_for_selected_year() -> tuple[
        int,
        list[str],
        dict[str, list[Decimal]],
        dict[str, list[int]],
        list[Decimal],
        list[Decimal],
    ]:
        try:
            raw_y = int(stat_ref_year.get())
        except (TypeError, ValueError, tk.TclError):
            raw_y = _stat_y_max
        ry = max(_stat_y_min, min(_stat_y_max, raw_y))
        db = db_holder[0]
        cats_by_year = year_categories_map(db)
        sums_by_cat: dict[str, list[Decimal]] = {}
        counts_by_cat: dict[str, list[int]] = {}
        tot_pos_by_month = [Decimal("0")] * 12
        tot_neg_abs_by_month = [Decimal("0")] * 12
        twin_cat = frozenset(import_cancel_twin_balance_keys(db))

        for c in cats_by_year.get(ry, []) or []:
            nm = category_display_name(str(c.get("name") or "")).strip()
            if not nm or is_hidden_dotazione_category_name(nm) or _stat_category_excluded_from_summary(nm):
                continue
            sums_by_cat.setdefault(nm, [Decimal("0")] * 12)
            counts_by_cat.setdefault(nm, [0] * 12)

        for yb in db.get("years", []) or []:
            for rec in yb.get("records", []) or []:
                if record_skip_for_category_statistics_budget(rec, twin_cat):
                    continue
                d_iso = str(rec.get("date_iso") or "").strip()
                if len(d_iso) < 7:
                    continue
                if d_iso[:4] != f"{ry:04d}":
                    continue
                try:
                    m = int(d_iso[5:7])
                except (TypeError, ValueError):
                    continue
                if m < 1 or m > 12:
                    continue
                py = record_category_plan_year(rec, yb, fallback_year=ry)
                cat_name = category_name_for_record(rec, cats_by_year.get(py, [])).strip()
                if not cat_name or _stat_category_excluded_from_summary(cat_name):
                    continue
                amt = to_decimal(rec.get("amount_eur") or "0")
                sums_by_cat.setdefault(cat_name, [Decimal("0")] * 12)
                counts_by_cat.setdefault(cat_name, [0] * 12)
                sums_by_cat[cat_name][m - 1] += amt
                counts_by_cat[cat_name][m - 1] += 1
                if amt > 0:
                    tot_pos_by_month[m - 1] += amt
                elif amt < 0:
                    tot_neg_abs_by_month[m - 1] += -amt

        cat_names = sorted(sums_by_cat.keys(), key=lambda s: s.lower())
        return ry, cat_names, sums_by_cat, counts_by_cat, tot_pos_by_month, tot_neg_abs_by_month

    def _stat_open_single_category_pdf(cat_name: str) -> None:
        _mesi_abbrev_it = (
            "Gen",
            "Feb",
            "Mar",
            "Apr",
            "Mag",
            "Giu",
            "Lug",
            "Ago",
            "Set",
            "Ott",
            "Nov",
            "Dic",
        )
        ry, _cat_names, sums_by_cat, counts_by_cat, tot_pos_by_month, tot_neg_abs_by_month = (
            _stat_categories_for_selected_year()
        )
        monthly_signed = list(sums_by_cat.get(cat_name, [Decimal("0")] * 12))
        monthly_counts = list(counts_by_cat.get(cat_name, [0] * 12))
        month_idx = [i for i in range(12) if monthly_counts[i] > 0]
        if not month_idx:
            messagebox.showinfo(
                "Grafici per categoria",
                "Nessun movimento in questa categoria nei mesi dell'anno selezionato.",
                parent=root,
            )
            return

        n_months = len(month_idx)
        annual_signed = sum((monthly_signed[i] for i in month_idx), Decimal("0"))
        denom_is_pos = annual_signed >= 0
        abs_sign = Decimal("1") if denom_is_pos else Decimal("-1")
        monthly_abs_signed = [abs(v) * abs_sign for v in monthly_signed]
        sum_plotted = sum((monthly_abs_signed[i] for i in month_idx), Decimal("0"))
        avg_abs_signed = (sum_plotted / Decimal(str(n_months))).quantize(Decimal("0.01"))
        plot_delta = [monthly_abs_signed[i] - avg_abs_signed for i in month_idx]

        plot_abs = [monthly_abs_signed[i] for i in month_idx]
        labels = [_mesi_abbrev_it[i] for i in month_idx]

        pct_row: list[str] = []
        for i in month_idx:
            abs_val = abs(monthly_signed[i])
            den = tot_pos_by_month[i] if denom_is_pos else tot_neg_abs_by_month[i]
            pct_row.append(_stat_format_pct_category(abs_val, den))
        total_label = "entrate" if denom_is_pos else "uscite"

        try:
            _mpldir = data_workspace.app_support_dir() / "mpl_config"
            try:
                _mpldir.mkdir(parents=True, exist_ok=True)
            except OSError:
                _mpldir = Path(tempfile.gettempdir()) / "conti_cdc_mpl"
                _mpldir.mkdir(parents=True, exist_ok=True)
            os.environ["MPLCONFIGDIR"] = str(_mpldir)
            import matplotlib

            matplotlib.use("Agg", force=True)
            from matplotlib.backends.backend_agg import FigureCanvasAgg
            from matplotlib.figure import Figure
            from matplotlib.patches import Patch
            from matplotlib.ticker import FuncFormatter
            import numpy as _np
            from matplotlib.colors import hsv_to_rgb
        except Exception as exc:  # pragma: no cover
            messagebox.showerror(
                "Grafici per categoria",
                f"Serve matplotlib (pip install matplotlib).\n{exc!s}",
                parent=root,
            )
            return

        nome = (_stat_charts_user_name(cur_db()) or "").strip() or "utente"
        cat_line = _pdf_safe_text(cat_name)
        avg_fig_txt = format_saldo_cell("€", avg_abs_signed)
        t_line1 = f"STATISTICHE CONTI DI CASA {nome} — anno {ry}"
        t_line2 = (
            f"Valori e variazioni mensili: «{cat_line}» · media {avg_fig_txt} "
            f"· in tabella % su totale mensile {total_label}."
        )
        st_title = t_line1 + "\n" + t_line2

        fig = Figure(figsize=(12.8, 8.2), dpi=100)
        gs = fig.add_gridspec(3, 1, left=0.1, right=0.9, top=0.98, bottom=0.02, height_ratios=[0.1, 1, 0.22], hspace=0.38)
        ax_title = fig.add_subplot(gs[0, 0])
        ax = fig.add_subplot(gs[1, 0])
        ax_bottom = fig.add_subplot(gs[2, 0])
        ax_title.set_axis_off()
        ax_bottom.set_axis_off()
        ax_title.text(
            0.5,
            0.5,
            st_title,
            transform=ax_title.transAxes,
            ha="center",
            va="center",
            fontsize=9.2,
            fontweight="normal",
            linespacing=1.25,
        )

        n_b = len(month_idx)
        colors_abs: list[tuple] = []
        edge_abs: list[tuple] = []
        colors_dlt: list[tuple] = []
        edge_dlt: list[tuple] = []
        for j in range(n_b):
            h0 = (j + 0.5) / max(n_b, 1)
            d = tuple(float(x) for x in hsv_to_rgb(_np.array([h0, 0.76, 0.5])))
            l_ = tuple(float(x) for x in hsv_to_rgb(_np.array([h0, 0.46, 0.85])))
            colors_abs.append(d)
            colors_dlt.append(l_)
            edge_abs.append(tuple(float(min(1.0, c * 0.72)) for c in d))
            edge_dlt.append(tuple(float(min(1.0, c * 0.72)) for c in l_))

        x = list(range(len(month_idx)))
        bar_w = 0.36
        f_abs = [float(v) for v in plot_abs]
        f_delta = [float(v) for v in plot_delta]

        bars_abs = ax.bar(
            [i - bar_w / 2 for i in x],
            f_abs,
            bar_w,
            color=colors_abs,
            edgecolor=edge_abs,
            linewidth=0.5,
            zorder=2,
        )
        bars_delta = ax.bar(
            [i + bar_w / 2 for i in x],
            f_delta,
            bar_w,
            color=colors_dlt,
            edgecolor=edge_dlt,
            linewidth=0.5,
            zorder=2,
        )

        def _euro_axis_fmt(v: float, _p: object) -> str:
            try:
                return f"{format_euro_it(Decimal(str(v)))} €"
            except Exception:
                return f"{v:.0f} €"

        ax.yaxis.set_major_formatter(FuncFormatter(_euro_axis_fmt))
        ax.axhline(0.0, color="#555555", linewidth=0.7, zorder=1)
        ax.grid(True, axis="y", alpha=0.3, zorder=0)
        ax.set_xticks(x)
        ax.set_xticklabels(labels, fontsize=8.5, rotation=0, ha="center")
        ax.set_xlabel("Mese", labelpad=6, fontsize=8.8)
        ax.spines["top"].set_visible(False)
        ax.spines["right"].set_visible(False)

        def _label_bars(bars: object, vals: list[Decimal]) -> None:
            for i, p in enumerate(bars.patches):
                ddec = vals[i]
                if abs(float(p.get_height() or 0.0)) < 1e-12 and ddec == 0:
                    continue
                tip = p.get_y() + p.get_height()
                xc = p.get_x() + p.get_width() * 0.5
                if float(p.get_height()) >= 0:
                    offy, va = 4, "bottom"
                else:
                    offy, va = -4, "top"
                ax.annotate(
                    format_saldo_cell("€", ddec),
                    (xc, tip),
                    xytext=(0, offy),
                    textcoords="offset points",
                    ha="center",
                    va=va,
                    rotation=90,
                    fontsize=7.1,
                    color="#1a1a1a",
                    zorder=3,
                )

        _label_bars(bars_abs, plot_abs)
        _label_bars(bars_delta, plot_delta)

        tbl_lbl = f"% sul totale mensile\ndelle {total_label}"
        pct_table = ax_bottom.table(
            cellText=[pct_row],
            rowLabels=[tbl_lbl],
            cellLoc="center",
            rowLoc="right",
            bbox=(0.02, 0.74, 0.96, 0.24),
        )
        pct_table.auto_set_font_size(False)
        pct_table.set_fontsize(7.1)
        for (_r, _c), cell in pct_table.get_celld().items():
            cell.set_edgecolor("#8a8a8a")
            cell.set_linewidth(0.45)
            cell.set_facecolor("#f6f6f6" if _c == -1 else "#ffffff")
            if _c == -1:
                tcell = cell.get_text()
                tcell.set_fontweight("bold")
                tcell.set_multialignment("right")
                tcell.set_ha("right")

        h1 = Patch(
            facecolor=(0.2, 0.2, 0.2),
            edgecolor=(0.1, 0.1, 0.1),
            label="Valore assoluto mensile (mese, barra più scura)",
        )
        h2 = Patch(
            facecolor=(0.75, 0.75, 0.75),
            edgecolor=(0.55, 0.55, 0.55),
            label="Variazione rispetto alla media (mese, barra più chiara)",
        )
        ax_bottom.legend(
            handles=[h1, h2],
            loc="upper center",
            bbox_to_anchor=(0.5, 0.51),
            ncol=2,
            fontsize=6.8,
            frameon=True,
            framealpha=0.95,
            borderaxespad=0.1,
            columnspacing=0.6,
        )

        try:
            canvas = FigureCanvasAgg(fig)
            canvas.draw()
            fd, pdf_path = tempfile.mkstemp(prefix="conti_categoria_mensile_", suffix=".pdf", dir=tempfile.gettempdir())
            os.close(fd)
            fig.savefig(
                pdf_path,
                format="pdf",
                metadata={"Title": _pdf_safe_text(f"Statistiche categoria {cat_name} - anno {ry}")},
            )
            _open_generated_pdf(str(Path(pdf_path).resolve()))
        except Exception as exc:
            messagebox.showerror("Grafici per categoria", f"Salvataggio del PDF non riuscito.\n{exc!s}", parent=root)

    def _stat_open_category_chart_menu(_e: tk.Event | None = None) -> None:
        _ry, cat_names, _sums, _counts, _tot_pos, _tot_neg = _stat_categories_for_selected_year()
        if not cat_names:
            messagebox.showinfo(
                "Grafici per categoria",
                "Nessuna categoria disponibile per l'anno selezionato.",
                parent=root,
            )
            return
        menu = tk.Menu(root, tearoff=0)
        for cat in cat_names:
            menu.add_command(label=cat, command=lambda c=cat: _stat_open_single_category_pdf(c))
        try:
            if _e is not None:
                menu.tk_popup(_e.x_root, _e.y_root + 4)
            else:
                x = stat_category_chart_btn.winfo_rootx()
                y = stat_category_chart_btn.winfo_rooty() + stat_category_chart_btn.winfo_height()
                menu.tk_popup(x, y)
        finally:
            menu.grab_release()

    def _stat_category_history_available_categories() -> list[str]:
        """Solo categorie presenti in almeno una registrazione non annullata (niente voci «vuote» dal solo piano)."""
        db = db_holder[0]
        cats_by_year = year_categories_map(db)
        twin_cat = frozenset(import_cancel_twin_balance_keys(db))
        out: set[str] = set()
        for yb in db.get("years", []) or []:
            for rec in yb.get("records", []) or []:
                if record_skip_for_category_statistics_budget(rec, twin_cat):
                    continue
                py = record_category_plan_year(rec, yb)
                cat_name = category_name_for_record(rec, cats_by_year.get(py, [])).strip()
                if not cat_name or is_hidden_dotazione_category_name(cat_name) or _stat_category_excluded_from_summary(cat_name):
                    continue
                out.add(cat_name)
        return sorted(out, key=lambda s: s.lower())

    def _stat_category_history_bar(value: Decimal, max_abs: Decimal, *, width: int = 30) -> str:
        if max_abs <= 0 or value == 0:
            return "."
        n = max(1, int((abs(value) / max_abs * Decimal(str(width))).to_integral_value(rounding=ROUND_HALF_UP)))
        bar = "█" * min(width, n)
        return ("> " if value > 0 else "< ") + bar

    def _stat_category_history_rows_for_selected() -> tuple[list[str], list[tuple[str, str, str]], str]:
        db = db_holder[0]
        selected = str(stat_category_history_var.get() or "").strip()
        years = sorted(
            {
                int(yb.get("year", 0) or 0)
                for yb in db.get("years", []) or []
                if int(yb.get("year", 0) or 0) > 0
            },
            reverse=True,
        )
        if not selected or not years:
            return ["Anno", "Saldo categoria", "Andamento annuale"], [], selected
        cats_by_year = year_categories_map(db)
        present_years: set[int] = set()
        sums_by_year: dict[int, Decimal] = {y: Decimal("0") for y in years}
        selected_key = selected.lower()
        twin_cat = frozenset(import_cancel_twin_balance_keys(db))

        for y in years:
            for c in cats_by_year.get(y, []) or []:
                nm = category_display_name(str(c.get("name") or "")).strip()
                if nm.lower() == selected_key:
                    present_years.add(y)
                    break

        for yb in db.get("years", []) or []:
            for rec in yb.get("records", []) or []:
                if record_skip_for_category_statistics_budget(rec, twin_cat):
                    continue
                d_iso = str(rec.get("date_iso") or "").strip()
                if len(d_iso) < 4 or not d_iso[:4].isdigit():
                    continue
                y = int(d_iso[:4])
                if y not in sums_by_year:
                    continue
                py = record_category_plan_year(rec, yb, fallback_year=y)
                cat_name = category_name_for_record(rec, cats_by_year.get(py, [])).strip()
                if cat_name.lower() != selected_key:
                    continue
                sums_by_year[y] += to_decimal(rec.get("amount_eur") or "0")

        max_abs = max((abs(v) for v in sums_by_year.values()), default=Decimal("0"))
        rows: list[tuple[str, str, str]] = []
        total = Decimal("0")
        for y in years:
            if y not in present_years:
                rows.append((str(y), "—", ""))
                continue
            value = sums_by_year.get(y, Decimal("0"))
            total += value
            rows.append((str(y), _stat_cell_eur(value), _stat_category_history_bar(value, max_abs)))
        rows.append(("Totale", _stat_cell_eur(total), ""))
        return ["Anno", selected, "Andamento annuale"], rows, selected

    def _stat_category_history_aggregate_rows_for_needle(
        needle: str,
    ) -> tuple[list[str], list[tuple[str, str, str]], str]:
        """Come ``_stat_category_history_rows_for_selected``, ma somma importi di tutte le categorie il cui nome contiene la stringa (case insensitive)."""
        db = db_holder[0]
        nl = (needle or "").strip().lower()
        if not nl:
            return ["Anno", "Saldo categorie aggregate", "Andamento annuale"], [], ""
        years = sorted(
            {
                int(yb.get("year", 0) or 0)
                for yb in db.get("years", []) or []
                if int(yb.get("year", 0) or 0) > 0
            },
            reverse=True,
        )
        if not years:
            return ["Anno", f"Σ «{needle.strip()}»", "Andamento annuale"], [], needle.strip()

        cats_by_year = year_categories_map(db)
        present_years: set[int] = set()
        sums_by_year: dict[int, Decimal] = {y: Decimal("0") for y in years}
        twin_cat = frozenset(import_cancel_twin_balance_keys(db))

        for y in years:
            for c in cats_by_year.get(y, []) or []:
                nm = category_display_name(str(c.get("name") or "")).strip()
                if not nm or is_hidden_dotazione_category_name(nm) or _stat_category_excluded_from_summary(nm):
                    continue
                if nl in nm.lower():
                    present_years.add(y)
                    break

        for yb in db.get("years", []) or []:
            for rec in yb.get("records", []) or []:
                if record_skip_for_category_statistics_budget(rec, twin_cat):
                    continue
                d_iso = str(rec.get("date_iso") or "").strip()
                if len(d_iso) < 4 or not d_iso[:4].isdigit():
                    continue
                y = int(d_iso[:4])
                if y not in sums_by_year:
                    continue
                py = record_category_plan_year(rec, yb, fallback_year=y)
                cat_name = category_name_for_record(rec, cats_by_year.get(py, [])).strip()
                if not cat_name or is_hidden_dotazione_category_name(cat_name) or _stat_category_excluded_from_summary(
                    cat_name
                ):
                    continue
                if nl not in cat_name.lower():
                    continue
                sums_by_year[y] += to_decimal(rec.get("amount_eur") or "0")

        max_abs = max((abs(v) for v in sums_by_year.values()), default=Decimal("0"))
        rows_out: list[tuple[str, str, str]] = []
        total = Decimal("0")
        lbl = f"Σ «{(needle or '').strip()}»"
        for y in years:
            if y not in present_years:
                rows_out.append((str(y), "—", ""))
                continue
            value = sums_by_year.get(y, Decimal("0"))
            total += value
            rows_out.append((str(y), _stat_cell_eur(value), _stat_category_history_bar(value, max_abs)))
        rows_out.append(("Totale", _stat_cell_eur(total), ""))
        return ["Anno", lbl, "Andamento annuale"], rows_out, (needle or "").strip()

    def _stat_category_history_print_data() -> tuple[str, list[tuple[int, Decimal | None]], Decimal, Decimal] | None:
        selected = str(stat_category_history_var.get() or "").strip()
        if not selected:
            return None
        heads, rows, _selected = _stat_category_history_rows_for_selected()
        if not rows:
            return None
        values: list[tuple[int, Decimal | None]] = []
        total = Decimal("0")
        max_abs = Decimal("0")
        for year_label, value_label, _bar_label in rows:
            if year_label == "Totale":
                continue
            if not str(year_label).isdigit():
                continue
            if value_label == "—":
                values.append((int(year_label), None))
                continue
            try:
                value = parse_amount(value_label.replace("€", "").strip())
            except Exception:
                value = Decimal("0")
            values.append((int(year_label), value))
            total += value
            max_abs = max(max_abs, abs(value))
        return heads[1], values, total, max_abs

    def _stat_print_category_history_table(intro_plain: str) -> bool:
        data = _stat_category_history_print_data()
        if data is None:
            return False
        selected, rows, total, max_abs = data
        main_title = f"Categorie per anno - {selected}"
        try:
            from fpdf import FPDF
            from fpdf.enums import XPos, YPos
        except ImportError:
            return False
        try:
            pdf = FPDF(orientation="P", unit="mm", format="A4")
            pdf.set_margins(12, 10, 12)
            pdf.set_auto_page_break(auto=True, margin=10)
            pdf.add_page()
            pdf.set_title(_pdf_safe_text(main_title)[:128])
            pdf.set_font("Helvetica", "B", 13)
            pdf.cell(0, 7, _pdf_safe_text(main_title), align="C", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
            pdf.set_font("Helvetica", "", 8)
            pdf.multi_cell(0, 4.0, _pdf_safe_text(intro_plain), align="C")
            pdf.ln(2)

            epw = pdf.epw
            table_w = min(epw, 142.0)
            x0 = pdf.l_margin + (epw - table_w) / 2.0
            w_year = 14.0
            w_val = 37.0
            w_bar = table_w - w_year - w_val
            row_h = 4.6
            head_h = 5.2

            def _draw_header() -> None:
                pdf.set_x(x0)
                pdf.set_font("Helvetica", "B", 7.2)
                pdf.set_text_color(0, 0, 0)
                pdf.set_fill_color(227, 242, 253)
                pdf.cell(w_year, head_h, "Anno", border=1, align="L", fill=True)
                pdf.cell(w_val, head_h, "Saldo categoria", border=1, align="R", fill=True)
                pdf.cell(w_bar, head_h, "Andamento annuale", border=1, align="L", fill=True)
                pdf.ln(head_h)

            _draw_header()
            for year_label, value in rows:
                if pdf.get_y() > 278:
                    pdf.add_page()
                    _draw_header()
                pdf.set_x(x0)
                pdf.set_font("Helvetica", "", 7.2)
                pdf.set_text_color(0, 0, 0)
                pdf.cell(w_year, row_h, str(year_label), border=1, align="L")
                if value is None:
                    pdf.set_text_color(80, 80, 80)
                    pdf.cell(w_val, row_h, "-", border=1, align="R")
                    pdf.cell(w_bar, row_h, "", border=1, align="L")
                    pdf.ln(row_h)
                    continue
                pdf.set_text_color(0, 100, 0) if value > 0 else pdf.set_text_color(178, 34, 34) if value < 0 else pdf.set_text_color(0, 0, 0)
                pdf.cell(w_val, row_h, _pdf_safe_text(_stat_cell_eur(value)), border=1, align="R")
                bar_x = pdf.get_x()
                bar_y = pdf.get_y()
                pdf.set_text_color(0, 0, 0)
                pdf.cell(w_bar, row_h, "", border=1, align="L")
                if max_abs > 0 and value != 0:
                    if value > 0:
                        pdf.set_fill_color(46, 125, 50)
                    else:
                        pdf.set_fill_color(178, 34, 34)
                    bw = max(1.5, float(abs(value) / max_abs) * (w_bar - 5.0))
                    pdf.rect(bar_x + 2.0, bar_y + 1.2, bw, row_h - 2.4, style="F")
                pdf.ln(row_h)

            if pdf.get_y() > 278:
                pdf.add_page()
            pdf.set_x(x0)
            pdf.set_font("Helvetica", "B", 7.4)
            pdf.set_fill_color(240, 240, 240)
            pdf.set_text_color(0, 0, 0)
            pdf.cell(w_year, row_h, "TOTALE", border=1, align="L", fill=True)
            pdf.set_text_color(0, 100, 0) if total > 0 else pdf.set_text_color(178, 34, 34) if total < 0 else pdf.set_text_color(0, 0, 0)
            pdf.cell(w_val, row_h, _pdf_safe_text(_stat_cell_eur(total)), border=1, align="R", fill=True)
            pdf.set_text_color(0, 0, 0)
            pdf.cell(w_bar, row_h, "", border=1, align="L", fill=True)

            fd, out_path = tempfile.mkstemp(suffix=".pdf", prefix="categorie_per_anno_")
            os.close(fd)
            pdf.output(out_path)
            _open_generated_pdf(out_path)
            return True
        except Exception:
            return False

