        if platform.system() == "Darwin":
            n = max(-14, min(14, -d))
        else:
            n = int(-d / 120)
            if n == 0:
                n = -1 if d > 0 else 1
            n = max(-12, min(12, n))
        _aiuto_txt.yview_scroll(n, "units")
        return "break"

