    def _pre_2022_category_fingerprint(d: dict) -> tuple[object, ...]:
        """Snapshot (anni < 2022) di piano categorie e campi categoria sulle righe, per verifiche di non-intervento su legacy."""
        parts: list[object] = []
        for yb in sorted((d.get("years") or []), key=lambda x: int(x.get("year", 0) or 0)):
            y = int(yb.get("year", 0) or 0)
            if y >= 2022:
                continue
            c_rows: list[tuple[str, str, str]] = []
            for c in (yb.get("categories") or []):
                c_rows.append(
                    (
                        str(c.get("code", "") or "").strip(),
                        str(c.get("name", "") or ""),
                        str(c.get("note", "") or c.get("category_note", "") or ""),
                    )
                )
            c_rows.sort(key=lambda t: t[0])
            rec_rows: list[tuple[str, str, str]] = []
            for r in (yb.get("records") or []):
                rec_rows.append(
                    (
                        str(r.get("category_code", "") or ""),
                        str(r.get("category_name", "") or ""),
                        str(r.get("legacy_registration_key", "") or "").strip(),
                    )
                )
            rec_rows.sort()
            parts.append((y, tuple(c_rows), tuple(rec_rows)))
        return tuple(parts)

    def _plan_legacy_categories_consistency_guard(
        context_label: str, *, pre2022_unchanged_if_matches_db: dict | None = None
    ) -> bool:
        """Blocco diagnostico: evita salvataggi quando i dati legacy categorie risultano incoerenti.

        Se ``pre2022_unchanged_if_matches_db`` è il DB **prima** di un'operazione che, per design, non tocca
        l'esercizio < 2022 (es. rinomina categoria solo da 2022 in poi), e lo snapshot pre-2022 del DB
        attuale coincide, non confrontiamo con l'export JSON: evitiamo blocchi dovuti a drift preesistente
        rispetto al file o a falsi allarmi, senza però omettere il controllo quando sì modifica il pre-2022.
        """
        d = cur_db()
        if pre2022_unchanged_if_matches_db is not None:
            if _pre_2022_category_fingerprint(d) == _pre_2022_category_fingerprint(pre2022_unchanged_if_matches_db):
                return True
        legacy_json = data_workspace.default_legacy_json_output()
        if not legacy_json.is_file():
            return True
        try:
            legacy_obj = json.loads(legacy_json.read_text(encoding="utf-8"))
        except Exception:
            return True
        legacy_years = {int(y.get("year", 0) or 0): y for y in (legacy_obj.get("years") or [])}
        legacy_by_key: dict[str, tuple[str, str]] = {}
        for y in legacy_obj.get("years") or []:
            yy = int(y.get("year", 0) or 0)
            if yy >= 2022:
                continue
            for r in y.get("records") or []:
                lk = str(r.get("legacy_registration_key") or "").strip()
                if lk:
                    legacy_by_key[lk] = (str(r.get("category_code") or ""), str(r.get("category_name") or ""))
        rec_mismatch = 0
        chart_mismatch_years: list[int] = []
        mismatch_records: list[dict[str, object]] = []
        chart_samples: list[dict[str, str | int]] = []
        for y in d.get("years") or []:
            yy = int(y.get("year", 0) or 0)
            if yy >= 2022:
                continue
            ly = legacy_years.get(yy)
            if ly is None:
                continue
            cur_map: dict[str, tuple[str, str]] = {}
            for c in y.get("categories") or []:
                code = str(c.get("code", "")).strip()
                if code:
                    cur_map[code] = (str(c.get("name") or ""), str(c.get("note") or c.get("category_note") or ""))
            leg_map: dict[str, tuple[str, str]] = {}
            for c in ly.get("categories") or []:
                code = str(c.get("code", "")).strip()
                if code:
                    leg_map[code] = (str(c.get("name") or ""), str(c.get("note") or c.get("category_note") or ""))
            if cur_map != leg_map:
                chart_mismatch_years.append(yy)
                if len(chart_samples) < 20:
                    for code in sorted(set(cur_map) | set(leg_map)):
                        if cur_map.get(code) == leg_map.get(code):
                            continue
                        chart_samples.append(
                            {
                                "year": yy,
                                "code": code,
                                "current_name": (cur_map.get(code) or ("", ""))[0],
                                "legacy_name": (leg_map.get(code) or ("", ""))[0],
                            }
                        )
                        if len(chart_samples) >= 20:
                            break
            for r in y.get("records") or []:
                lk = str(r.get("legacy_registration_key") or "").strip()
                if not lk:
                    continue
                expect = legacy_by_key.get(lk)
                if expect is None:
                    continue
                cur_code = str(r.get("category_code") or "")
                cur_name = str(r.get("category_name") or "")
                if cur_code == expect[0] and cur_name == expect[1]:
                    continue
                rec_mismatch += 1
                sk = record_legacy_stable_key(r)
                mismatch_records.append(
                    {
                        "year": yy,
                        "date_iso": str(r.get("date_iso") or ""),
                        "stable_key": sk,
                        "legacy_registration_key": lk,
                        "current_category_code": cur_code,
                        "legacy_category_code": expect[0],
                        "current_category_name": cur_name,
                        "legacy_category_name": expect[1],
                    }
                )
        records_all = [r for y in (d.get("years") or []) for r in (y.get("records") or [])]
        records_all.sort(key=record_merge_sort_key)
        reg_seq_map = unified_registration_sequence_map(records_all)
        for mr in mismatch_records:
            sk0 = str(mr.get("stable_key") or "")
            ng = reg_seq_map.get(sk0)
            mr["registration_number_global"] = int(ng) if ng is not None else None
        rec_samples = mismatch_records[:40]
        _MAX_MISMATCH_JSON_ROWS = 2500
        rec_details = mismatch_records[:_MAX_MISMATCH_JSON_ROWS]
        rec_details_truncated = len(mismatch_records) > _MAX_MISMATCH_JSON_ROWS
        if rec_mismatch == 0 and not chart_mismatch_years:
            return True
        diag_dir = data_workspace.legacy_import_dir() / "diagnostics"
        try:
            diag_dir.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        report_path = diag_dir / f"legacy_category_guard_{ts}.json"
        report = {
            "context": context_label,
            "generated_at": datetime.now().isoformat(timespec="seconds"),
            "legacy_source": str(legacy_json),
            "record_mismatch_count_pre2022": rec_mismatch,
            "chart_mismatch_years_pre2022": sorted(chart_mismatch_years),
            "record_samples": rec_samples,
            "record_mismatch_details": rec_details,
            "record_mismatch_details_truncated": rec_details_truncated,
            "record_mismatch_details_omitted_count": max(0, len(mismatch_records) - len(rec_details)),
            "chart_samples": chart_samples,
            "guidance_it": [
                "Ogni voce in record_mismatch_details è una registrazione pre-2022 il cui codice/nome categoria nel database "
                "non coincide con l’export JSON legacy (stesso legacy_registration_key).",
                "registration_number_global corrisponde al «Reg.#» globale della pagina Movimenti (ricerca per registrazione o elenco). "
                "date_iso è la data contabile; stable_key è la chiave interna del record.",
                "Per intervenire: ripristinare codice e nome categoria come nel file legacy (re-import da Opzioni se opportuno), "
                "oppure correggere manualmente le registrazioni indicate usando Movimenti / Modifica registrazione.",
                "Se chart_mismatch_years_pre2022 non è vuoto, il piano categorie di quell’anno nel DB differisce dal legacy: "
                "va riallineato anche il piano oltre alle singole riglie.",
            ],
        }
        try:
            report_path.write_text(json.dumps(report, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
            report_s = str(report_path)
        except Exception:
            report_s = "(report non scrivibile)"
        messagebox.showerror(
            "Controllo coerenza legacy",
            "Operazione annullata: rilevate incoerenze legacy sulle categorie "
            f"(contesto: {context_label}).\n\n"
            f"Registrazioni pre-2022 con mismatch: {rec_mismatch}\n"
            f"Anni pre-2022 con piano categorie disallineato: {len(chart_mismatch_years)}\n\n"
            "Nel report JSON trovi record_mismatch_details: per ogni riga, registration_number_global "
            "è lo stesso «Reg.#» della pagina Movimenti; date_iso e legacy vs attuale categoria spiegano la divergenza.\n\n"
            f"Report: {report_s}",
            parent=root,
        )
        return False

    def _correct_plan_category(cd: str) -> None:
        row = next((r for r in plan_cat_rows if str(r["code"]) == str(cd)), None)
        if row is None:
            return
        d = cur_db()
        if not d.get("years"):
            messagebox.showwarning("Categorie", "Nessun anno contabile nel database.", parent=root)
            return
        d_before = copy.deepcopy(d)
        on = str(row.get("orig_name", "") or "")
        on_fmt = format_category_chart_name_stored(on)
        orig_note = str(row.get("orig_note", "") or "")
        name_locked = bool(row.get("locked"))
        if name_locked:
            cur_fmt = format_category_chart_name_stored(row["name"].get() or "")
            if cur_fmt != on_fmt:
                messagebox.showwarning("Categorie", "Il nome di questa categoria non è modificabile.", parent=root)
                row["name"].set(on_fmt)
                return
            nm = on_fmt
        else:
            nm = format_category_chart_name_stored(row["name"].get() or "")
            row["name"].set(nm)
        nt = format_category_note_stored(row["note"].get() or "")
        row["note"].set(nt)
        nt_or_none = nt if nt else None
        nt0 = format_category_note_stored(orig_note)
        raw_name_changed = (row["name"].get() or "") != str(row.get("orig_display_name", "") or "")
        raw_note_changed = (row["note"].get() or "") != str(row.get("orig_display_note", "") or "")
        if nm == on_fmt and nt == nt0 and not (raw_name_changed or raw_note_changed):
            messagebox.showinfo("Categorie", "Nessuna modifica da applicare.", parent=root)
            return
        disp_name = category_display_name(nm).strip() or category_display_name(on_fmt).strip() or str(cd)
        if not messagebox.askokcancel(
            "Categorie",
            "Confermando: il piano categorie (nome e nota) si aggiorna negli anni da "
            f"{CATEGORY_PLAN_MUTATE_MIN_YEAR} in avanti. Le registrazioni coinvolte sono solo quelle con stesso "
            f"codice categoria e nome identico al testo attuale (come in griglia), sempre dal {CATEGORY_PLAN_MUTATE_MIN_YEAR} in avanti; "
            "gli esercizi precedenti, coerenti con l’import legacy, non vengono alterati.",
            parent=root,
        ):
            return
        if not name_locked and nm != on_fmt:
            if not plan_conti_names_have_attinenza(on_fmt, nm):
                messagebox.showwarning(
                    "Categorie",
                    "Il nuovo nome deve condividere almeno 4 lettere consecutive con il nome attuale.",
                    parent=root,
                )
                row["name"].set(on_fmt)
                return
        propagate_category_chart_by_code(
            d, cd, nm, nt_or_none, min_year_inclusive=CATEGORY_PLAN_MUTATE_MIN_YEAR
        )
        if not name_locked and nm != on:
            sync_record_category_names_if_identical_old(
                d, cd, on, nm, min_year=CATEGORY_PLAN_MUTATE_MIN_YEAR
            )
        if not _plan_legacy_categories_consistency_guard(
            "correzione singola categoria", pre2022_unchanged_if_matches_db=d_before
        ):
            db_holder[0] = d_before
            _reload_plan_conti_form()
            return
        try:
            save_encrypted_db_dual(
                d,
                Path(data_file_var.get()),
                Path(key_file_var.get()),
            )
        except Exception as exc:
            messagebox.showerror("Categorie", str(exc), parent=root)
            return
        plan_conti_status_var.set("Correzione salvata.")
        _movements_dirty[0] = True
        try:
            refresh_balance_footer()
            refresh_category_account_dropdowns()
        except Exception:
            pass
        _reload_plan_conti_form()

    def _reload_plan_conti_form() -> None:
        for w in plan_cat_grid.winfo_children():
            w.destroy()
        for w in plan_acc_grid.winfo_children():
            w.destroy()
        plan_cat_rows.clear()
        plan_acc_rows.clear()
        d = cur_db()
        if not d.get("years"):
            plan_conti_status_var.set(
                "Nessun anno contabile nel database: usa Import legacy oppure crea l’anno con la prima registrazione "
                "(anno contabile scelto in immissione; il programma aggiunge l’anno al bisogno)."
            )
            return
        plan_conti_status_var.set("")
        ttk.Label(plan_cat_grid, text="Cod.", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=0, sticky="w", padx=2, pady=2)
        ttk.Label(plan_cat_grid, text="Nome categoria", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=1, sticky="w", padx=2, pady=2)
        ttk.Label(plan_cat_grid, text="Nota", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=2, sticky="w", padx=2, pady=2)
        ttk.Label(plan_cat_grid, text="", width=10).grid(row=0, column=3, sticky="w")
        visible_cats = merged_categories_for_plan_editor(d)

        cat_row_idx = 0
        for c in visible_cats:
            code = str(c.get("code", ""))
            cat_row_idx += 1
            ri = cat_row_idx
            raw_nm = str(c.get("name", "") or "")
            raw_nt = category_row_merged_note(c)
            if plan_conti_category_name_locked(raw_nm):
                nn = " ".join(category_display_name(raw_nm).lower().replace(".", " ").replace("/", " / ").split())
                if ("girata conto / conto" in nn or "girata conto conto" in nn) and not raw_nt:
                    raw_nt = GIRATA_NOTE_DEFAULT
            name_locked = plan_conti_category_name_locked(raw_nm)
            note_locked = plan_conti_category_note_locked(raw_nm)
            disp_nm = format_category_chart_name_stored(raw_nm)
            disp_nt = format_category_note_stored(raw_nt)
            nv = tk.StringVar(value=disp_nm)
            vv = tk.StringVar(value=disp_nt)
            plan_cat_rows.append(
                {
                    "code": code,
                    "name": nv,
                    "note": vv,
                    "orig_name": raw_nm,
                    "orig_note": raw_nt,
                    "orig_display_name": disp_nm,
                    "orig_display_note": disp_nt,
                    "locked": name_locked,
                }
            )
            ttk.Label(plan_cat_grid, text=code).grid(row=ri, column=0, sticky="w", padx=2, pady=1)
            est_nm = "readonly" if name_locked else "normal"
            est_nt = "readonly" if note_locked else "normal"
            ent_nm = ttk.Entry(plan_cat_grid, textvariable=nv, width=28, state=est_nm)
            ent_nt = ttk.Entry(plan_cat_grid, textvariable=vv, width=36, state=est_nt)
            ent_nm.grid(row=ri, column=1, sticky="we", padx=2, pady=1)
            ent_nt.grid(row=ri, column=2, sticky="we", padx=2, pady=1)
            if not name_locked:
                bind_entry_all_chars_uppercase(nv, ent_nm)
            if not note_locked:
                bind_entry_first_char_uppercase(vv, ent_nt)

            def _corr_cat(cd: str = code) -> None:
                _correct_plan_category(cd)

            _corr_bg = "#b71c1c"
            _corr_fg = "#ffffff"
            corr_lbl = tk.Label(
                plan_cat_grid,
                text="Correggi",
                font=("TkDefaultFont", 9, "bold"),
                bg=_corr_bg,
                fg=_corr_fg,
                padx=10,
                pady=3,
                cursor="hand2",
            )
            corr_lbl.grid(row=ri, column=3, sticky="w", padx=2, pady=1)
            corr_lbl.bind("<Button-1>", lambda _e, fn=_corr_cat: fn())

        ttk.Label(plan_acc_grid, text="Cod.", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=0, sticky="w", padx=2, pady=2)
        ttk.Label(plan_acc_grid, text="Nome conto", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=1, sticky="w", padx=2, pady=2)
        ttk.Label(plan_acc_grid, text="Stato", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=2, sticky="w", padx=2, pady=2)
        ttk.Label(plan_acc_grid, text="Conto di riferimento (carta)", font=("TkDefaultFont", 10, "bold")).grid(
            row=0, column=3, sticky="w", padx=2, pady=2
        )
        ttk.Label(plan_acc_grid, text="Saldo", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=4, sticky="w", padx=2, pady=2)
        ttk.Label(
            plan_acc_grid,
            text="Nomi dei file pdf per le verifiche automatiche",
            font=("TkDefaultFont", 10, "bold"),
            wraplength=280,
        ).grid(row=0, column=5, sticky="nw", padx=2, pady=2)
        ttk.Label(plan_acc_grid, text="Congela", font=("TkDefaultFont", 10, "bold")).grid(row=0, column=6, sticky="w", padx=2, pady=2)
        merged_acc = merge_account_charts_across_years(d)
        acc_name_by_code: dict[str, str] = {}
        for ax in merged_acc:
            c_ax = str(ax.get("code", "")).strip()
            if c_ax:
                acc_name_by_code[c_ax] = str(ax.get("name", "") or "").strip()
        _plan_acc_red_bg = "#b71c1c"
        _plan_acc_red_fg = "#ffffff"
        _plan_acc_red_dis_bg = "#bdbdbd"
        _plan_acc_red_dis_fg = "#e0e0e0"
        for ri, a in enumerate(merged_acc, start=1):
            raw_code = a.get("code")
            code = str(raw_code).strip() if raw_code is not None else ""
            raw_nm = str(a.get("name", "") or "")
            locked_acc = plan_conti_account_is_cassa(raw_nm)
            is_frozen = bool(a.get("frozen"))
            stem_raw = str(a.get("estratti_pdf_stem") or "").strip()
            stem_v = tk.StringVar(value=stem_raw)
            bal = None if not code else account_balance_for_code_latest_chart(d, code)
            bal_s = "—" if bal is None else format_euro_it(bal)
            is_cc_row = bool(a.get("credit_card"))
            ref_cd = str(a.get("credit_card_reference_code") or "").strip()
            if is_cc_row and ref_cd:
                ref_disp = (acc_name_by_code.get(ref_cd) or "").strip() or f"(codice {ref_cd})"
            elif is_cc_row:
                ref_disp = "—"
            else:
                ref_disp = ""
            plan_acc_rows.append(
                {
                    "code": code,
                    "orig_name": raw_nm,
                    "estratti_pdf_stem": stem_v,
                    "locked_acc": locked_acc,
                    "frozen_acc": is_frozen,
                }
            )
            ttk.Label(plan_acc_grid, text=(code or "—")).grid(row=ri, column=0, sticky="w", padx=2, pady=1)
            row_locked = locked_acc or is_frozen
            ttk.Label(plan_acc_grid, text=raw_nm, wraplength=360).grid(row=ri, column=1, sticky="we", padx=2, pady=1)
            if is_frozen:
                ttk.Label(
                    plan_acc_grid,
                    text="Congelato",
                    font=("TkDefaultFont", 10, "bold"),
                    foreground="#6d4c41",
                ).grid(row=ri, column=2, sticky="w", padx=2, pady=1)
            else:
                ttk.Label(plan_acc_grid, text="—", foreground="#888888").grid(row=ri, column=2, sticky="w", padx=2, pady=1)
            ttk.Label(plan_acc_grid, text=ref_disp, wraplength=280).grid(row=ri, column=3, sticky="we", padx=2, pady=1)
            ttk.Label(plan_acc_grid, text=bal_s).grid(row=ri, column=4, sticky="w", padx=2, pady=1)
            stem_est = "readonly" if row_locked else "normal"
            ttk.Entry(plan_acc_grid, textvariable=stem_v, width=28, state=stem_est).grid(
                row=ri, column=5, sticky="we", padx=2, pady=1
            )

            def _freeze_acc(cd: str = code, nm_chk: str = raw_nm, fr: bool = is_frozen) -> None:
                dd = cur_db()
                dd_before = copy.deepcopy(dd)
                if plan_conti_account_is_cassa(nm_chk):
                    messagebox.showwarning("Conti", "Il conto Cassa non può essere congelato.", parent=root)
                    return
                if _is_virtuale_account(nm_chk):
                    messagebox.showwarning("Conti", "Il conto VIRTUALE non può essere congelato.", parent=root)
                    return
                acc_nm = nm_chk.strip() or cd
                if account_code_is_frozen(dd, cd):
                    messagebox.showinfo("Conti", "Il conto risulta già congelato.", parent=root)
                    return
                ok, err = account_meets_three_month_idle_for_freeze_or_remove(dd, cd)
                if not ok:
                    messagebox.showwarning("Congela conto", err, parent=root)
                    return
                if not messagebox.askyesno(
                    "Congela conto",
                    f"Congelare il conto «{acc_nm}» (codice {cd})?\n\n"
                    "Le registrazioni di quel conto restano invariate e restano visibili nelle ricerche in Movimenti; "
                    "il conto non comparirà più nei Saldi né nei menu delle nuove registrazioni.",
                    parent=root,
                ):
                    return
                propagate_account_frozen_by_code(dd, cd, frozen=True)
                if not _plan_legacy_categories_consistency_guard("congelamento conto"):
                    db_holder[0] = dd_before
                    _reload_plan_conti_form()
                    return
                try:
                    save_encrypted_db_dual(
                        dd,
                        Path(data_file_var.get()),
                        Path(key_file_var.get()),
                    )
                except Exception as exc:
                    propagate_account_frozen_by_code(dd, cd, frozen=False)
                    messagebox.showerror("Conti", str(exc), parent=root)
                    return
                plan_conti_status_var.set("Conto congelato e database salvato.")
                _movements_dirty[0] = True
                try:
                    refresh_balance_footer()
                    refresh_category_account_dropdowns()
                except Exception:
                    pass
                _reload_plan_conti_form()

            fz_active = not (locked_acc or is_frozen)
            if is_frozen:
                ttk.Label(plan_acc_grid, text="—", foreground="#888888", width=8).grid(
                    row=ri, column=6, sticky="w", padx=2, pady=1
                )
            else:
                fz_lbl = tk.Label(
                    plan_acc_grid,
                    text="Congela",
                    font=("TkDefaultFont", 9, "bold"),
                    bg=_plan_acc_red_bg if fz_active else _plan_acc_red_dis_bg,
                    fg=_plan_acc_red_fg if fz_active else _plan_acc_red_dis_fg,
                    padx=10,
                    pady=3,
                    cursor="hand2" if fz_active else "arrow",
                )
                fz_lbl.grid(row=ri, column=6, sticky="w", padx=2, pady=1)
                if fz_active:
                    fz_lbl.bind("<Button-1>", lambda _e, fn=_freeze_acc: fn())
        plan_cat_grid.columnconfigure(1, weight=1)
        plan_cat_grid.columnconfigure(2, weight=1)
        plan_acc_grid.columnconfigure(1, weight=1)
        plan_acc_grid.columnconfigure(3, weight=1)
        plan_acc_grid.columnconfigure(5, weight=1)
        for _cnv in (plan_cat_canvas, plan_acc_canvas):
            try:
                _cnv.configure(scrollregion=_cnv.bbox("all"))
            except Exception:
                pass
        try:
            _plan_cat_bind_wheel_like_movimenti()
        except Exception:
            pass

    def _discard_unsaved_plan_pdf_stems() -> None:
        """Ripristina in griglia solo i nomi base PDF dal DB in memoria (non tocca la scheda Categorie)."""
        d = cur_db()
        if not plan_acc_rows:
            plan_conti_status_var.set("Nessun conto in elenco.")
            return
        for row in plan_acc_rows:
            code = str(row.get("code") or "").strip()
            stem_v = row.get("estratti_pdf_stem")
            if not isinstance(stem_v, tk.StringVar):
                continue
            stem_v.set(account_estratti_pdf_stem_for_code(d, code))
        plan_conti_status_var.set(
            "Nomi base PDF ripristinati dal database in memoria (per salvarli nel file cifrato usa «Salva nomi base pdf»)."
        )

    def _plan_category_form_is_dirty() -> bool:
        for row in plan_cat_rows:
            on = str(row.get("orig_name", "") or "")
            name_locked = bool(row.get("locked"))
            on_fmt = format_category_chart_name_stored(on)
            orig_note = str(row.get("orig_note", "") or "")
            nt0 = format_category_note_stored(orig_note)
            if name_locked:
                nm = on_fmt
            else:
                nm = format_category_chart_name_stored(row["name"].get() or "")
            nt = format_category_note_stored(row["note"].get() or "")
            if nm == on_fmt and nt == nt0 and on.strip() == nm:
                continue
            return True
        return False

    def _plan_accounts_pdf_is_dirty() -> bool:
        d = cur_db()
        for row in plan_acc_rows:
            if row.get("frozen_acc"):
                continue
            code = str(row.get("code") or "").strip()
            stem_v = row.get("estratti_pdf_stem")
            if not isinstance(stem_v, tk.StringVar):
                continue
            if (stem_v.get() or "").strip() != account_estratti_pdf_stem_for_code(d, code).strip():
                return True
        return False

    def _save_plan_accounts_pdf_only() -> bool:
        d = cur_db()
        if not d.get("years"):
            messagebox.showwarning("Conti", "Nessun anno contabile nel database.", parent=root)
            return False
        for row in plan_acc_rows:
            if row.get("frozen_acc"):
                continue
            code = str(row["code"])
            stem_v = row.get("estratti_pdf_stem")
            if isinstance(stem_v, tk.StringVar):
                propagate_account_estratti_pdf_stem_by_code(d, code, stem_v.get() or "")
        try:
            save_encrypted_db_dual(
                d,
                Path(data_file_var.get()),
                Path(key_file_var.get()),
            )
        except Exception as exc:
            messagebox.showerror("Conti", str(exc), parent=root)
            return False
        plan_conti_status_var.set("Nomi base PDF salvati nel file cifrato.")
        _movements_dirty[0] = True
        try:
            refresh_balance_footer()
            refresh_category_account_dropdowns()
        except Exception:
            pass
        _reload_plan_conti_form()
        return True

    def _plan_tab_leave_before_navigate(old: tk.Widget, new: tk.Widget) -> bool:
        if old is plan_categorie_frame and new is not plan_categorie_frame:
            if plan_cat_rows and _plan_category_form_is_dirty():
                r = messagebox.askyesno(
                    "Categorie",
                    "Le modifiche alla scheda Categorie non sono state confermate.\n\n"
                    "Ogni riga va salvata con il tasto «Correggi».\n\n"
                    "Vuoi uscire e scartare le modifiche non confermate?",
                    parent=root,
                )
                if not r:
                    return False
                _reload_plan_conti_form()
        if old is plan_conti_frame and new is not plan_conti_frame:
            if plan_acc_rows and _plan_accounts_pdf_is_dirty():
                r = messagebox.askyesnocancel(
                    "Conti",
                    "Le modifiche ai nomi base dei file PDF non sono state salvate sul file cifrato.\n\n"
                    "Salvare prima di uscire?",
                    parent=root,
                )
                if r is None:
                    return False
                if r:
                    return _save_plan_accounts_pdf_only()
                _discard_unsaved_plan_pdf_stems()
        return True

    _plan_tab_leave_check[0] = _plan_tab_leave_before_navigate

    def _add_blank_category() -> None:
        d = cur_db()
        if not d.get("years"):
            messagebox.showwarning("Categorie e conti", "Crea prima un anno contabile.", parent=root)
            return
        if len(merged_categories_for_plan_editor(d)) >= MAX_CATEGORIES_COUNT:
            messagebox.showwarning(
                "Categorie e conti",
                f"Hai già raggiunto il massimo di {MAX_CATEGORIES_COUNT} categorie.",
                parent=root,
            )
            return
        nums: list[int] = []
        for yb in d.get("years") or []:
            for c in yb.get("categories") or []:
                s = str(c.get("code", "")).strip()
                if s.isdigit() or (s.startswith("-") and s[1:].isdigit()):
                    try:
                        nums.append(int(s))
                    except ValueError:
                        pass
        nxt = max(nums) + 1 if nums else 1
        nxt_s = str(nxt)

        def _existing_stored_names() -> set[str]:
            out: set[str] = set()
            for c in merged_categories_for_plan_editor(d):
                out.add(format_category_chart_name_stored(str(c.get("name", "") or "")))
            return out

        top = tk.Toplevel(root)
        top.title("Nuova categoria")
        top.transient(root)
        top.grab_set()
        frm = ttk.Frame(top, padding=12)
        frm.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frm, text=f"Codice assegnato: {nxt_s}").grid(row=0, column=0, columnspan=2, sticky="w", pady=(0, 8))
        ttk.Label(frm, text="Nome categoria (+ o - davanti, poi testo)").grid(row=1, column=0, sticky="nw", pady=2)
        ttk.Label(frm, text="Nota categoria").grid(row=2, column=0, sticky="nw", pady=2)
        nm_var = tk.StringVar(value="-")
        nt_var = tk.StringVar()
        ent_nm = ttk.Entry(frm, textvariable=nm_var, width=42)
        ent_nt = ttk.Entry(frm, textvariable=nt_var, width=42)
        ent_nm.grid(row=1, column=1, sticky="we", padx=(8, 0), pady=2)
        ent_nt.grid(row=2, column=1, sticky="we", padx=(8, 0), pady=2)
        bind_entry_all_chars_uppercase(nm_var, ent_nm)
        bind_entry_first_char_uppercase(nt_var, ent_nt)
        frm.columnconfigure(1, weight=1)
        hint = (
            f"Massimo {MAX_CATEGORY_NAME_LEN} caratteri per il nome e {MAX_CATEGORY_NOTE_LEN} per la nota; "
            "nome tutto maiuscolo dopo il segno; prima lettera della nota maiuscola."
        )
        ttk.Label(frm, text=hint, wraplength=520, foreground="#555555").grid(
            row=3, column=0, columnspan=2, sticky="w", pady=(8, 4)
        )
        err_lbl = ttk.Label(frm, text="", foreground="#b00020", wraplength=520)
        err_lbl.grid(row=4, column=0, columnspan=2, sticky="w", pady=(0, 8))

        def _cat_name_clip_live(*_args: object) -> None:
            cur = nm_var.get() or ""
            clipped = clip_text(cur, MAX_CATEGORY_NAME_LEN)
            if clipped != cur:
                try:
                    pos = ent_nm.index(tk.INSERT)
                except Exception:
                    pos = None
                nm_var.set(clipped)
                if pos is not None:
                    try:
                        ent_nm.icursor(min(pos, len(clipped)))
                    except Exception:
                        pass

        def _cat_name_keypress_limit(event: tk.Event) -> str | None:
            keysym = str(getattr(event, "keysym", "") or "")
            if keysym in (
                "BackSpace",
                "Delete",
                "Left",
                "Right",
                "Up",
                "Down",
                "Home",
                "End",
                "Tab",
                "ISO_Left_Tab",
                "Return",
                "KP_Enter",
                "Escape",
            ):
                return None
            ch = str(getattr(event, "char", "") or "")
            if not ch or ord(ch) < 32:
                return None
            w = event.widget
            cur = nm_var.get() or ""
            try:
                a = int(w.index("sel.first"))
                b = int(w.index("sel.last"))
            except tk.TclError:
                try:
                    p = int(w.index(tk.INSERT))
                except tk.TclError:
                    return None
                a = b = p
            if len(cur) - (b - a) >= MAX_CATEGORY_NAME_LEN:
                return "break"
            return None

        def _cat_name_paste_limit(event: tk.Event) -> str:
            try:
                clip = event.widget.clipboard_get()
            except tk.TclError:
                return "break"
            if not clip:
                return "break"
            w = event.widget
            cur = nm_var.get() or ""
            try:
                a = int(w.index("sel.first"))
                b = int(w.index("sel.last"))
            except tk.TclError:
                try:
                    p = int(w.index(tk.INSERT))
                except tk.TclError:
                    return "break"
                a = b = p
            room = max(0, MAX_CATEGORY_NAME_LEN - (len(cur) - (b - a)))
            if room <= 0:
                return "break"
            ins = clip_text(str(clip), room)
            merged = cur[:a] + ins + cur[b:]
            nm_var.set(clip_text(merged, MAX_CATEGORY_NAME_LEN))
            try:
                w.icursor(min(a + len(ins), len(nm_var.get() or "")))
            except tk.TclError:
                pass
            return "break"

        nm_var.trace_add("write", _cat_name_clip_live)
        ent_nm.bind("<KeyPress>", _cat_name_keypress_limit, add="+")
        ent_nm.bind("<<Paste>>", _cat_name_paste_limit, add="+")

        def _try_add() -> None:
            err_lbl.configure(text="")
            raw_nm = (nm_var.get() or "").strip()
            if not raw_nm or raw_nm[0] not in "+-":
                err_lbl.configure(text="Il nome deve iniziare con + o -.")
                return
            if len(raw_nm) > MAX_CATEGORY_NAME_LEN:
                err_lbl.configure(text=f"Nome troppo lungo (massimo {MAX_CATEGORY_NAME_LEN} caratteri).")
                return
            raw_nt = nt_var.get() or ""
            if len(raw_nt) > MAX_CATEGORY_NOTE_LEN:
                err_lbl.configure(text=f"Nota troppo lunga (massimo {MAX_CATEGORY_NOTE_LEN} caratteri).")
                return
            nm = format_category_chart_name_stored(raw_nm)
            nt = format_category_note_stored(raw_nt)
            nt_or_none = nt if nt else None
            if nm in _existing_stored_names():
                err_lbl.configure(text="Esiste già una categoria con questo nome (dopo formattazione).")
                return
            new_cat = {"code": nxt_s, "name": nm, "note": nt_or_none}
            d_before = copy.deepcopy(d)
            _append_category_all_years(new_cat)
            if not _plan_legacy_categories_consistency_guard("aggiunta categoria"):
                db_holder[0] = d_before
                _reload_plan_conti_form()
                err_lbl.configure(text="Coerenza legacy non valida: modifica annullata.")
                return
            try:
                save_encrypted_db_dual(
                    d,
                    Path(data_file_var.get()),
                    Path(key_file_var.get()),
                )
            except Exception as exc:
                err_lbl.configure(text=f"Salvataggio non riuscito: {exc}")
                return
            top.destroy()
            _movements_dirty[0] = True
            try:
                refresh_balance_footer()
                refresh_category_account_dropdowns()
            except Exception:
                pass
            _reload_plan_conti_form()
            plan_conti_status_var.set("Categoria aggiunta e salvata nel file cifrato.")

        btns = ttk.Frame(frm)
        btns.grid(row=5, column=0, columnspan=2, sticky="e", pady=(4, 0))
        ttk.Button(btns, text="Annulla", command=top.destroy).pack(side=tk.RIGHT, padx=(8, 0))
        ttk.Button(btns, text="Aggiungi", command=_try_add).pack(side=tk.RIGHT)
        try:
            ent_nm.focus_set()
        except Exception:
            pass

    def _add_blank_account() -> None:
        """``wiz`` memorizza apertura carta di credito + codice conto di riferimento per l'append al piano."""
        wiz: dict[str, object] = {"credit_card": False, "credit_card_reference_code": ""}

        def _reference_accounts_for_credit_card(dd: dict) -> list[tuple[str, str]]:
            out: list[tuple[str, str]] = []
            for a in merge_account_charts_across_years(dd):
                code = str(a.get("code", "")).strip()
                name = str(a.get("name", "") or "").strip()
                if not code or not name:
                    continue
                if bool(a.get("credit_card")):
                    continue
                nu = name.upper()
                if nu == "CASSA" or nu == str(VIRTUALE_ACCOUNT_NAME).upper():
                    continue
                out.append((name, code))
            return out

        def _base_new_acc(name_stored: str) -> dict:
            acc: dict[str, object] = {"code": nxt_s, "name": name_stored}
            if bool(wiz.get("credit_card")) and str(wiz.get("credit_card_reference_code") or "").strip():
                acc["credit_card"] = True
                acc["credit_card_reference_code"] = str(wiz.get("credit_card_reference_code") or "").strip()
            return acc

        d0 = cur_db()
        if not d0.get("years"):
            messagebox.showwarning("Conti", "Crea prima un anno contabile.", parent=root)
            return
        if len(merge_account_charts_across_years(d0)) >= MAX_ACCOUNTS_COUNT:
            messagebox.showwarning(
                "Conti",
                f"Hai già raggiunto il massimo di {MAX_ACCOUNTS_COUNT} conti.",
                parent=root,
            )
            return
        nums: list[int] = []
        for yb in d0.get("years") or []:
            for a in yb.get("accounts") or []:
                s = str(a.get("code", "")).strip()
                if s.isdigit():
                    try:
                        nums.append(int(s))
                    except ValueError:
                        pass
        nxt = max(nums) + 1 if nums else 1
        nxt_s = str(nxt)

        def _existing_account_names_upper(dd: dict) -> set[str]:
            return {
                str(a.get("name", "") or "").strip().upper()
                for a in merge_account_charts_across_years(dd)
                if str(a.get("name", "") or "").strip()
            }

        def _save_db_after_change() -> bool:
            try:
                save_encrypted_db_dual(
                    cur_db(),
                    Path(data_file_var.get()),
                    Path(key_file_var.get()),
                )
            except Exception as exc:
                messagebox.showerror("Conti", str(exc), parent=root)
                return False
            return True

        def _refresh_after_account_change() -> None:
            _movements_dirty[0] = True
            try:
                refresh_balance_footer()
                refresh_category_account_dropdowns()
            except Exception:
                pass
            _reload_plan_conti_form()

        def _open_cat_note_step(name_stored: str, amt: Decimal) -> None:
            cat_opts_all, _, cat_note_by_code, _, cat_raw_name_by_code = _cat_and_acc_options()
            cat_opts = [(n, c) for n, c in cat_opts_all if not _is_giro_label(n)]
            if not cat_opts:
                messagebox.showerror(
                    "Conti",
                    "Non ci sono categorie utilizzabili (escluse le girate): impossibile creare la registrazione.\n"
                    "Ripeti l’operazione con importo zero per creare solo il conto.",
                    parent=root,
                )
                return
            top_c = tk.Toplevel(root)
            top_c.title("Nuovo conto — registrazione")
            top_c.transient(root)
            top_c.grab_set()
            fc = ttk.Frame(top_c, padding=14)
            fc.pack(fill=tk.BOTH, expand=True)
            ttk.Label(
                fc,
                text=f"Importo: {format_euro_it(amt)} €. Completa data, categoria e nota per la prima registrazione.",
                wraplength=440,
            ).grid(row=0, column=0, columnspan=2, sticky="w", pady=(0, 8))
            dmin, dmax = immissione_date_bounds()
            today_clamped = max(dmin, min(date.today(), dmax))
            date_var = tk.StringVar(value=to_italian_date(today_clamped.isoformat()))
            ttk.Label(fc, text="Data (gg/mm/aaaa)").grid(row=1, column=0, sticky="nw", pady=2)
            drow = ttk.Frame(fc)
            drow.grid(row=1, column=1, sticky="w", padx=(8, 0), pady=2)
            ent_dt = ttk.Entry(drow, textvariable=date_var, width=12)
            ent_dt.pack(side=tk.LEFT)

            def _open_add_acc_calendar() -> None:
                cur_iso = parse_italian_ddmmyyyy_to_iso(date_var.get()) or today_clamped.isoformat()
                try:
                    cur_d = date.fromisoformat(cur_iso)
                except Exception:
                    cur_d = today_clamped
                cur_d = max(dmin, min(cur_d, dmax))

                def _on_dt_chosen(dsel: date) -> None:
                    date_var.set(to_italian_date(dsel.isoformat()))

                cal = build_immissione_calendar_toplevel(
                    top_c,
                    title="Data registrazione",
                    anchor=ent_dt,
                    field_min=dmin,
                    field_max=dmax,
                    current=cur_d,
                    on_date_chosen=_on_dt_chosen,
                    ui_font=("TkDefaultFont", 11, "bold"),
                )
                try:
                    cal.transient(top_c)
                except Exception:
                    pass
                try:
                    top_c.grab_release()
                except Exception:
                    pass
                try:
                    cal.grab_set()
                except Exception:
                    pass
                try:
                    cal.bind("<Destroy>", lambda _e: top_c.grab_set(), add="+")
                except Exception:
                    pass

            ttk.Button(drow, text="Calendario…", command=_open_add_acc_calendar).pack(side=tk.LEFT, padx=(8, 0))
            cat_var = tk.StringVar(value=cat_opts[0][0])
            ttk.Label(fc, text="Categoria").grid(row=2, column=0, sticky="nw", pady=2)
            cb = ttk.Combobox(
                fc, textvariable=cat_var, width=34, state="readonly", values=[n for n, _ in cat_opts]
            )
            cb.grid(row=2, column=1, sticky="we", padx=(8, 0), pady=2)
            nt_var = tk.StringVar()
            ttk.Label(fc, text="Nota registrazione").grid(row=3, column=0, sticky="nw", pady=2)
            ent_nt = ttk.Entry(fc, textvariable=nt_var, width=40)
            ent_nt.grid(row=3, column=1, sticky="we", padx=(8, 0), pady=2)
            bind_limited_single_line_text_entry(ent_nt, nt_var, max_len=MAX_RECORD_NOTE_LEN, strip_edges=False)
            bind_entry_first_char_uppercase(nt_var, ent_nt)
            fc.columnconfigure(1, weight=1)
            er2 = ttk.Label(fc, text="", foreground="#b00020", wraplength=440)
            er2.grid(row=4, column=0, columnspan=2, sticky="w", pady=(0, 6))

            def _code_for_cat_display(display_name: str) -> str:
                dn = (display_name or "").strip()
                for n, c in cat_opts:
                    if n == dn:
                        return c
                return str(cat_opts[0][1])

            def _cc_close() -> None:
                try:
                    top_c.destroy()
                except Exception:
                    pass

            def _cc_ok() -> None:
                er2.configure(text="")
                cc = _code_for_cat_display(cat_var.get())
                if not cc:
                    er2.configure(text="Selezionare una categoria.")
                    return
                note = format_record_note_stored(
                    sanitize_single_line_text(nt_var.get() or "", max_len=MAX_RECORD_NOTE_LEN, strip_edges=False)
                )
                if not note.strip():
                    er2.configure(text="La nota è obbligatoria.")
                    return
                raw_d = (date_var.get() or "").strip()
                d_iso = parse_italian_ddmmyyyy_to_iso(raw_d)
                if not d_iso:
                    er2.configure(text="Data non valida (usare gg/mm/aaaa).")
                    return
                try:
                    dpar = date.fromisoformat(d_iso)
                except Exception:
                    er2.configure(text="Data non valida.")
                    return
                if dpar < dmin or dpar > dmax:
                    er2.configure(
                        text=(
                            "La data è fuori dall’intervallo consentito per l’immissione: "
                            f"da {to_italian_date(dmin.isoformat())} a {to_italian_date(dmax.isoformat())}."
                        )
                    )
                    return
                ty = dpar.year
                dd = cur_db()
                new_acc = _base_new_acc(name_stored)
                _append_account_all_years(new_acc)
                y_bucket = _ensure_year_bucket(ty)
                y_records = y_bucket.get("records", [])
                source_index = max((int(r.get("source_index", 0) or 0) for r in y_records), default=0) + 1
                reg_n = _next_registration_number()
                cat_name_raw = str(cat_raw_name_by_code.get(cc) or "").strip() or cat_var.get().strip()
                cat_note = str(cat_note_by_code.get(cc) or "")
                acc_name_stored = name_stored
                for ax in merge_account_charts_across_years(dd):
                    if str(ax.get("code", "")).strip() == nxt_s:
                        acc_name_stored = str(ax.get("name", "") or "").strip()
                        break
                rec = {
                    "year": ty,
                    "source_folder": "APP",
                    "source_file": "manual",
                    "source_index": source_index,
                    "legacy_registration_number": source_index,
                    "legacy_registration_key": f"APP:add_account:{ty}:{source_index}",
                    "registration_number": reg_n,
                    "date_iso": d_iso,
                    "category_code": cc,
                    "category_name": cat_name_raw,
                    "category_note": cat_note,
                    "account_primary_code": nxt_s,
                    "account_primary_flags": "",
                    "account_primary_with_flags": nxt_s,
                    "account_primary_name": acc_name_stored,
                    "account_secondary_code": "",
                    "account_secondary_flags": "",
                    "account_secondary_with_flags": "",
                    "account_secondary_name": "",
                    "amount_eur": format_money(amt),
                    "amount_lire_original": None,
                    "note": note,
                    "cheque": "-",
                    "raw_flags": "",
                    "is_cancelled": False,
                    "source_currency": "E",
                    "display_currency": "E",
                    "display_amount": format_money(amt),
                    "raw_record": "",
                    "is_virtuale_discharge": False,
                }
                y_bucket.setdefault("records", []).append(rec)
                if not _save_db_after_change():
                    return
                plan_conti_status_var.set("Conto e prima registrazione salvati nel file cifrato.")
                _refresh_after_account_change()
                _cc_close()

            bfc = ttk.Frame(fc)
            bfc.grid(row=5, column=0, columnspan=2, sticky="e", pady=(8, 0))
            ttk.Button(bfc, text="Annulla", command=_cc_close).pack(side=tk.RIGHT, padx=(8, 0))
            ttk.Button(bfc, text="Salva", command=_cc_ok).pack(side=tk.RIGHT)
            try:
                ent_dt.focus_set()
            except Exception:
                pass

        def _open_amount_step(name_stored: str) -> None:
            top_am = tk.Toplevel(root)
            top_am.title("Nuovo conto — importo")
            top_am.transient(root)
            top_am.grab_set()
            fr = ttk.Frame(top_am, padding=14)
            fr.pack(fill=tk.BOTH, expand=True)
            ttk.Label(
                fr,
                text=(
                    "Importo iniziale sul nuovo conto (euro, formato italiano).\n"
                    "Se l’importo è zero, viene creato solo il conto (nessuna registrazione)."
                ),
                wraplength=440,
            ).grid(row=0, column=0, columnspan=2, sticky="w", pady=(0, 8))
            amt_var = tk.StringVar(value="-")
            ent_am = ttk.Entry(fr, textvariable=amt_var, width=24)
            ent_am.grid(row=1, column=0, sticky="w", pady=4)
            err = ttk.Label(fr, text="", foreground="#b00020", wraplength=440)
            err.grid(row=2, column=0, columnspan=2, sticky="w", pady=(0, 6))

            def _amount_validate_on_focus_out(_e: tk.Event | None = None) -> None:
                raw_live = (amt_var.get() or "").strip()
                if raw_live in ("+", "-"):
                    return
                try:
                    normalized = normalize_euro_input(raw_live)
                except Exception:
                    err.configure(text="Importo non valido: usa formato euro (es. -1.234,56).")
                    return
                err.configure(text="")
                amt_var.set(format_euro_it(normalized))

            ent_am.bind("<FocusOut>", _amount_validate_on_focus_out, add="+")

            _amt_partial_re = re.compile(r"^[+-](?:\d+)?(?:[.,]\d{0,2})?$")

            def _amt_next_text_for_keypress(event: tk.Event) -> str | None:
                w = event.widget
                cur = amt_var.get() or ""
                try:
                    a = int(w.index("sel.first"))
                    b = int(w.index("sel.last"))
                except tk.TclError:
                    a = b = -1
                keysym = str(getattr(event, "keysym", "") or "")
                ch = str(getattr(event, "char", "") or "")
                try:
                    pos = int(w.index(tk.INSERT))
                except tk.TclError:
                    pos = len(cur)

                if keysym == "BackSpace":
                    if a >= 0 and b >= 0:
                        return cur[:a] + cur[b:]
                    if pos <= 0:
                        return cur
                    return cur[: pos - 1] + cur[pos:]
                if keysym == "Delete":
                    if a >= 0 and b >= 0:
                        return cur[:a] + cur[b:]
                    if pos >= len(cur):
                        return cur
                    return cur[:pos] + cur[pos + 1 :]
                if ch and ord(ch) >= 32:
                    if a >= 0 and b >= 0:
                        return cur[:a] + ch + cur[b:]
                    return cur[:pos] + ch + cur[pos:]
                return None

            def _strict_amt_keypress(event: tk.Event) -> str | None:
                keysym = str(getattr(event, "keysym", "") or "")
                if keysym in ("Return", "KP_Enter"):
                    _am_ok()
                    return "break"
                if keysym in (
                    "Left",
                    "Right",
                    "Up",
                    "Down",
                    "Home",
                    "End",
                    "Tab",
                    "ISO_Left_Tab",
                    "Escape",
                ):
                    return None
                st = int(getattr(event, "state", 0) or 0)
                if st & (0x0004 | 0x0008 | 0x20000 | 0x100000):
                    return None
                ch = str(getattr(event, "char", "") or "")
                cur = amt_var.get() or ""
                w = event.widget

                if keysym in ("BackSpace", "Delete"):
                    nxt = _amt_next_text_for_keypress(event) or cur
                    if not nxt or nxt[0] not in "+-":
                        return "break"
                    if nxt in ("+", "-"):
                        amt_var.set(nxt)
                        try:
                            w.icursor(1)
                        except Exception:
                            pass
                        err.configure(text="")
                        return "break"
                    if not _amt_partial_re.fullmatch(nxt):
                        return "break"
                    return None

                if not ch or ord(ch) < 32:
                    return None

                if _euro_typed_char_is_sign(ch):
                    sig = _euro_sign_char_to_ascii(ch)
                    body = cur[1:] if cur.startswith(("+", "-")) else cur
                    amt_var.set(sig + body)
                    try:
                        w.icursor(1)
                    except Exception:
                        pass
                    err.configure(text="")
                    return "break"

                if ch not in "0123456789.,":
                    return "break"
                nxt = _amt_next_text_for_keypress(event)
                if nxt is None:
                    return "break"
                if not nxt or nxt[0] not in "+-":
                    return "break"
                if nxt in ("+", "-"):
                    return "break"
                if not _amt_partial_re.fullmatch(nxt):
                    return "break"
                body = nxt[1:]
                if body.count(".") + body.count(",") > 1:
                    return "break"
                if "." in body:
                    dec = body.split(".", 1)[1]
                    if len(dec) > 2:
                        return "break"
                if "," in body:
                    dec = body.split(",", 1)[1]
                    if len(dec) > 2:
                        return "break"
                err.configure(text="")
                return None

            def _strict_amt_paste(event: tk.Event) -> str:
                try:
                    clip = str(event.widget.clipboard_get() or "").strip().replace(" ", "")
                except tk.TclError:
                    return "break"
                clip = clip.replace("\u2212", "-").replace("\u2013", "-")
                if not clip:
                    return "break"
                w = event.widget
                cur = amt_var.get() or ""
                try:
                    a = int(w.index("sel.first"))
                    b = int(w.index("sel.last"))
                except tk.TclError:
                    try:
                        p = int(w.index(tk.INSERT))
                    except tk.TclError:
                        return "break"
                    a = b = p
                merged = cur[:a] + clip + cur[b:]
                if not _amt_partial_re.fullmatch(merged):
                    return "break"
                body = merged[1:]
                if body.count(".") + body.count(",") > 1:
                    return "break"
                if "." in body and len(body.split(".", 1)[1]) > 2:
                    return "break"
                if "," in body and len(body.split(",", 1)[1]) > 2:
                    return "break"
                amt_var.set(merged)
                try:
                    w.icursor(min(a + len(clip), len(merged)))
                except tk.TclError:
                    pass
                err.configure(text="")
                return "break"

            ent_am.bind("<KeyPress>", _strict_amt_keypress, add="+")
            ent_am.bind("<<Paste>>", _strict_amt_paste, add="+")

            def _am_close() -> None:
                try:
                    top_am.destroy()
                except Exception:
                    pass

            def _am_ok() -> None:
                err.configure(text="")
                raw = (amt_var.get() or "").strip()
                if raw == "":
                    err.configure(text="Inserire un importo (0 se non vuoi creare registrazioni).")
                    return
                try:
                    amt = normalize_euro_input(raw)
                except Exception as ex:
                    err.configure(text=str(ex))
                    return
                if amt == Decimal("0") or amt == Decimal("0.00"):
                    _append_account_all_years(_base_new_acc(name_stored))
                    if not _save_db_after_change():
                        return
                    plan_conti_status_var.set("Conto aggiunto (nessuna registrazione) e salvato nel file cifrato.")
                    _refresh_after_account_change()
                    _am_close()
                    return
                cat_opts_all, _, _, _, _ = _cat_and_acc_options()
                if not [(n, c) for n, c in cat_opts_all if not _is_giro_label(n)]:
                    err.configure(
                        text="Non ci sono categorie (non girate) per una registrazione: usa importo zero o aggiungi categorie."
                    )
                    return
                _am_close()
                _open_cat_note_step(name_stored, amt)

            bf = ttk.Frame(fr)
            bf.grid(row=3, column=0, columnspan=2, sticky="e", pady=(8, 0))
            ttk.Button(bf, text="Annulla", command=_am_close).pack(side=tk.RIGHT, padx=(8, 0))
            ttk.Button(bf, text="Continua", command=_am_ok).pack(side=tk.RIGHT)
            try:
                ent_am.focus_set()
                ent_am.icursor(1)
            except Exception:
                pass

        top_nm = tk.Toplevel(root)
