        top_nm.transient(root)
        top_nm.grab_set()
        frm = ttk.Frame(top_nm, padding=14)
        frm.pack(fill=tk.BOTH, expand=True)
        ttk.Label(
            frm,
            text=(
                f"Nome del nuovo conto (tutto maiuscolo; massimo {MAX_ACCOUNT_NAME_LEN} caratteri). "
                "Alla fine il nome sarà salvato e comparirà in immissione, ricerca e modifica."
            ),
            wraplength=440,
        ).grid(row=0, column=0, columnspan=2, sticky="w", pady=(0, 8))
        nm_var = tk.StringVar()
        ent_nm = ttk.Entry(frm, textvariable=nm_var, width=36)
        ent_nm.grid(row=1, column=0, columnspan=2, sticky="we", pady=4)
        bind_entry_all_chars_uppercase(nm_var, ent_nm)
        err_lbl = ttk.Label(frm, text="", foreground="#b00020", wraplength=440)
        err_lbl.grid(row=2, column=0, columnspan=2, sticky="w", pady=(0, 8))

        def _sanitize_account_name_live(raw_text: str) -> str:
            txt = (raw_text or "").upper()
            return "".join(ch for ch in txt if ch.isalpha())

        def _nm_keypress_filter(event: tk.Event) -> str | None:
            keysym = str(getattr(event, "keysym", "") or "")
            if keysym in (
                "BackSpace",
                "Delete",
                "Left",
                "Right",
                "Up",
                "Down",
                "Home",
                "End",
                "Tab",
                "ISO_Left_Tab",
                "Return",
                "KP_Enter",
                "Escape",
            ):
                return None
            st = int(getattr(event, "state", 0) or 0)
            if st & (0x0004 | 0x0008 | 0x20000 | 0x100000):
                return None
            ch = str(getattr(event, "char", "") or "")
            if not ch:
                return None
            if ch.isalpha():
                return None
            return "break"

        def _nm_paste_filter(event: tk.Event) -> str:
            try:
                clip = event.widget.clipboard_get()
            except tk.TclError:
                return "break"
            filtered = _sanitize_account_name_live(clip)
            if not filtered:
                return "break"
            w = event.widget
            cur = nm_var.get() or ""
            try:
                a = int(w.index("sel.first"))
                b = int(w.index("sel.last"))
            except tk.TclError:
                try:
                    p = int(w.index(tk.INSERT))
                except tk.TclError:
                    return "break"
                a = b = p
            merged = cur[:a] + filtered + cur[b:]
            merged = clip_text(merged, MAX_ACCOUNT_NAME_LEN)
            nm_var.set(merged)
            try:
                w.icursor(min(a + len(filtered), len(merged)))
            except tk.TclError:
                pass
            return "break"

        def _nm_live_cleanup(*_args: object) -> None:
            current = nm_var.get() or ""
            cleaned = clip_text(_sanitize_account_name_live(current), MAX_ACCOUNT_NAME_LEN)
            if cleaned != current:
                try:
                    pos = ent_nm.index(tk.INSERT)
                except Exception:
                    pos = None
                nm_var.set(cleaned)
                if pos is not None:
                    try:
                        ent_nm.icursor(min(pos, len(cleaned)))
                    except Exception:
                        pass

        ent_nm.bind("<KeyPress>", _nm_keypress_filter, add="+")
        ent_nm.bind("<<Paste>>", _nm_paste_filter, add="+")
        nm_var.trace_add("write", _nm_live_cleanup)

        def _nm_dismiss() -> None:
            wiz["credit_card"] = False
            wiz["credit_card_reference_code"] = ""
            try:
                top_nm.destroy()
            except Exception:
                pass

        def _nm_next() -> None:
            err_lbl.configure(text="")
            raw = (nm_var.get() or "").strip().upper()
            if not raw:
                err_lbl.configure(text="Inserire un nome conto.")
                return
            if len(raw) > MAX_ACCOUNT_NAME_LEN:
                err_lbl.configure(text=f"Nome troppo lungo (massimo {MAX_ACCOUNT_NAME_LEN} caratteri).")
                return
            stored = clip_text(raw, MAX_ACCOUNT_NAME_LEN)
            if stored.strip().upper() != raw:
                err_lbl.configure(text="Nome non valido dopo il taglio alla lunghezza massima.")
                return
            if stored.upper() in _existing_account_names_upper(cur_db()):
                err_lbl.configure(text="Esiste già un conto con questo nome (senza distinguere maiuscole/minuscole).")
                return
            _nm_dismiss()
            _open_amount_step(stored)

        def _open_cc_reference_step(name_stored: str) -> None:
            choices = _reference_accounts_for_credit_card(cur_db())
            if not choices:
                messagebox.showwarning(
                    "Conti",
                    "Non è disponibile alcun conto di riferimento: servono conti ordinari nel piano "
                    "(esclusi Cassa, VIRTUALE e altri conti carta di credito).",
                    parent=top_nm,
                )
                return

            def _code_for_ref_display(display_name: str) -> str:
                dn = (display_name or "").strip()
                for n, c in choices:
                    if n == dn:
                        return c
                return str(choices[0][1])

            top_ref = tk.Toplevel(top_nm)
            top_ref.title("Nuovo conto — carta di credito")
            top_ref.transient(top_nm)
            top_ref.grab_set()
            fr_ref = ttk.Frame(top_ref, padding=14)
