    def _get_ui_color_overrides() -> dict[str, str]:
        raw = cur_db().get(cdc_ui_theme._OVERRIDES_KEY) or {}
        if not isinstance(raw, dict):
            return {}
        out: dict[str, str] = {}
        for k, v in raw.items():
            if isinstance(k, str) and isinstance(v, str):
                out[k] = v
        return out

